                                                {sessionOptions.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                                            </select>
                                        </div>
                                    </div>
                                )) : <p className="text-sm text-text-secondary text-center py-4">Semua nomor lomba sudah terjadwal.</p>}
                            </div>
                        </div>
                    </div>
                </Card>
