import React, { useState, useEffect, useMemo } from 'react';
import { Card } from './ui/Card';
import { Button } from './ui/Button';
import { Spinner } from './ui/Spinner';
import { processParticipantUpload, getEvents, registerSwimmerToEvent } from '../services/databaseService';
import { formatEventName, formatTime, AGE_GROUP_OPTIONS } from '../constants';
import type { Swimmer, SwimEvent, CompetitionInfo } from '../types';
import { Gender } from '../types';
import { Input } from './ui/Input';
import { Select } from './ui/Select';
import { useNotification } from './ui/NotificationManager';

declare var XLSX: any; // From script tag

interface ParticipantsViewProps {
  swimmers: Swimmer[];
  events: SwimEvent[];
  onUploadSuccess: () => void;
  competitionInfo: CompetitionInfo | null; // Added competitionInfo
}

export const ParticipantsView: React.FC<ParticipantsViewProps> = ({ swimmers, events, onUploadSuccess, competitionInfo }) => {
  const [file, setFile] = useState<File | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [uploadResult, setUploadResult] = useState<{ newSwimmers: number; updatedSwimmers: number; errors: string[] } | null>(null);
  const [canDownload, setCanDownload] = useState(false);
  const { addNotification } = useNotification();

  // State for manual registration
  const [manualForm, setManualForm] = useState({ swimmerId: '', eventId: '', min: '99', sec: '99', ms: '99' });
  const [categoryFilter, setCategoryFilter] = useState<string>('all');

  // Dynamic Age Groups Logic
  const ageOptions = useMemo(() => {
      if (competitionInfo?.ageGroups) {
          return competitionInfo.ageGroups.split('\n').map(s => s.trim()).filter(Boolean);
      }
      return AGE_GROUP_OPTIONS;
  }, [competitionInfo]);

  useEffect(() => {
    setCanDownload(events.length > 0);
  }, [events]); 

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setUploadResult(null);
    }
  };

  const handleUpload = () => {
    if (!file) return;

    setIsProcessing(true);
    setUploadResult(null);
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = new Uint8Array(e.target.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const json = XLSX.utils.sheet_to_json(worksheet);

        const result = await processParticipantUpload(json);
        setUploadResult(result);
        if (result.errors.length === 0 && (result.newSwimmers > 0 || result.updatedSwimmers > 0)) {
            addNotification('File pendaftaran berhasil diproses!', 'success');
        } else if (result.errors.length > 0) {
            addNotification(`Impor selesai dengan ${result.errors.length} galat.`, 'error');
        }
        if (result.newSwimmers > 0 || result.updatedSwimmers > 0) {
          onUploadSuccess(); // Trigger global data refresh
        }
      } catch (error: any) {
        addNotification(`Gagal memproses file: ${error.message}`, 'error');
        setUploadResult({ newSwimmers: 0, updatedSwimmers: 0, errors: ['Gagal membaca atau memproses file.', error.message] });
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const downloadTemplate = async () => {
    if (typeof XLSX === 'undefined') {
        alert('Pustaka untuk membuat file Excel belum termuat. Periksa koneksi internet Anda dan muat ulang halaman.');
        return;
    }

    setIsDownloading(true);
    try {
        if (events.length === 0) {
             alert("Template tidak dapat dibuat karena belum ada nomor lomba. Silakan buat nomor lomba terlebih dahulu di menu 'Pengaturan Acara'.");
             return;
        }

        const templateData: any[] = [];
        const columnHeaders = {
            "Nama Atlet": "",
            "Tahun Lahir": "",
            "Jenis Kelamin (L/P)": "",
            "Nama Tim": "",
            "KU": "",
            "Nomor Lomba": "",
            "Waktu Unggulan (mm:ss.SS)": ""
        };

        const addSectionHeader = (title: string) => {
            templateData.push({ ...columnHeaders, "Nama Atlet": `--- ${title.toUpperCase()} ---` });
        };

        const defaultKU = ageOptions.length > 0 ? ageOptions[0] : "KU 1";

        // --- EXAMPLE: PERORANGAN PUTRA ---
        const maleEvents = events.filter(e => e.gender === Gender.MALE && !e.relayLegs);
        if (maleEvents.length > 0) {
            addSectionHeader("Contoh Pendaftaran Perorangan Putra");
            const exampleEvents = maleEvents.slice(0, 2); // Take up to 2 examples
            exampleEvents.forEach((event, index) => {
                templateData.push({
                    "Nama Atlet": "Budi Perkasa",
                    "Tahun Lahir": 2005,
                    "Jenis Kelamin (L/P)": "L",
                    "Nama Tim": "Tim Cepat",
                    "KU": defaultKU,
                    "Nomor Lomba": formatEventName(event),
                    "Waktu Unggulan (mm:ss.SS)": index === 0 ? "01:05.50" : "99:99.99"
                });
            });
            templateData.push(columnHeaders); // Spacer
        }

        // --- EXAMPLE: PERORANGAN PUTRI ---
        const femaleEvents = events.filter(e => e.gender === Gender.FEMALE && !e.relayLegs);
        if (femaleEvents.length > 0) {
            addSectionHeader("Contoh Pendaftaran Perorangan Putri");
            const exampleEvents = femaleEvents.slice(0, 2);
            exampleEvents.forEach((event, index) => {
                templateData.push({
                    "Nama Atlet": "Siti Cepat",
                    "Tahun Lahir": 2006,
                    "Jenis Kelamin (L/P)": "P",
                    "Nama Tim": "Tim Cepat",
                    "KU": defaultKU,
                    "Nomor Lomba": formatEventName(event),
                    "Waktu Unggulan (mm:ss.SS)": index === 0 ? "01:15.20" : "00:31.40"
                });
            });
            templateData.push(columnHeaders); // Spacer
        }

        // --- EXAMPLE: ESTAFET (RELAY) ---
        const relayMaleEvent = events.find(e => e.gender === Gender.MALE && e.relayLegs);
        const relayFemaleEvent = events.find(e => e.gender === Gender.FEMALE && e.relayLegs);
        const relayMixedEvent = events.find(e => e.gender === Gender.MIXED && e.relayLegs);

        if (relayMaleEvent || relayFemaleEvent || relayMixedEvent) {
            addSectionHeader("Contoh Pendaftaran Estafet (Relay)");
            templateData.push({
                ...columnHeaders,
                "Nama Atlet": "CATATAN: Untuk Estafet, 'Nama Atlet' diisi NAMA TIM, 'Tahun Lahir' dan 'KU' dikosongkan."
            });

            if (relayMaleEvent) {
                templateData.push({
                    "Nama Atlet": `Tim Putra Tim Cepat`,
                    "Tahun Lahir": "", // Intentionally blank for relays
                    "Jenis Kelamin (L/P)": "L", // Gender is used to identify the team type
                    "Nama Tim": "Tim Cepat",
                    "KU": "",
                    "Nomor Lomba": formatEventName(relayMaleEvent),
                    "Waktu Unggulan (mm:ss.SS)": "04:10.00"
                });
            }
            if (relayFemaleEvent) {
                templateData.push({
                    "Nama Atlet": `Tim Putri Tim Cepat`,
                    "Tahun Lahir": "",
                    "Jenis Kelamin (L/P)": "P",
                    "Nama Tim": "Tim Cepat",
                     "KU": "",
                    "Nomor Lomba": formatEventName(relayFemaleEvent),
                    "Waktu Unggulan (mm:ss.SS)": "04:30.00"
                });
            }
            if (relayMixedEvent) {
                templateData.push({
                    "Nama Atlet": `Tim Campuran Tim Cepat`,
                    "Tahun Lahir": "",
                    "Jenis Kelamin (L/P)": "L", // For mixed, can be L or P, often tied to team contact
                    "Nama Tim": "Tim Cepat",
                     "KU": "",
                    "Nomor Lomba": formatEventName(relayMixedEvent),
                    "Waktu Unggulan (mm:ss.SS)": "04:20.00"
                });
            }
            templateData.push(columnHeaders); // Spacer
        }

        // --- If no examples could be generated ---
        if (templateData.length === 0) {
             templateData.push({
                "Nama Atlet": "Contoh Nama",
                "Tahun Lahir": 2005,
                "Jenis Kelamin (L/P)": "L",
                "Nama Tim": "Tim Contoh",
                "KU": defaultKU,
                "Nomor Lomba": events.length > 0 ? formatEventName(events[0]) : "Tidak ada nomor lomba",
                "Waktu Unggulan (mm:ss.SS)": "01:25.50"
            });
        }

        const workbook = XLSX.utils.book_new();

        // --- Sheet 1: Template Pendaftaran ---
        const wsTemplate = XLSX.utils.json_to_sheet(templateData, { skipHeader: true }); // Use skipHeader and manually add it

        // Manually create the header row
        const header = ["Nama Atlet", "Tahun Lahir", "Jenis Kelamin (L/P)", "Nama Tim", "KU", "Nomor Lomba", "Waktu Unggulan (mm:ss.SS)"];
        XLSX.utils.sheet_add_aoa(wsTemplate, [header], { origin: "A1" });

        const maxRows = 2000;
        if (!wsTemplate['!dataValidation']) wsTemplate['!dataValidation'] = [];

        // Data validation for Race Name
        wsTemplate['!dataValidation'].push({
            sqref: `F2:F${maxRows}`, 
            opts: { type: 'list', allowBlank: false, formula1: `'Daftar Nomor Lomba'!$A$6:$A$${events.length + 6}`, showDropDown: true, error: 'Silakan pilih nomor lomba yang valid dari daftar.', errorTitle: 'Pilihan Tidak Valid' }
        });

        // Data validation for Gender
        wsTemplate['!dataValidation'].push({
            sqref: `C2:C${maxRows}`,
            opts: { type: 'list', allowBlank: false, formula1: `"L,P"`, showDropDown: true, error: 'Gunakan "L" untuk Laki-laki atau "P" untuk Perempuan.', errorTitle: 'Pilihan Tidak Valid'}
        });

        // Data validation for Age Group (KU) - NEW
        if (ageOptions.length > 0) {
             wsTemplate['!dataValidation'].push({
                sqref: `E2:E${maxRows}`,
                opts: { type: 'list', allowBlank: true, formula1: `'Daftar Nomor Lomba'!$C$6:$C$${ageOptions.length + 6}`, showDropDown: true, error: 'Silakan pilih KU yang valid dari daftar.', errorTitle: 'Pilihan Tidak Valid'}
            });
        }

        wsTemplate['!cols'] = [ { wch: 40 }, { wch: 15 }, { wch: 20 }, { wch: 30 }, { wch: 15 }, { wch: 50 }, { wch: 25 }];
        XLSX.utils.book_append_sheet(workbook, wsTemplate, "Template Pendaftaran");

        // --- Sheet 2: Daftar Nomor Lomba & KU ---
        const allEventsFormatted = events.sort((a,b) => formatEventName(a).localeCompare(formatEventName(b))).map(e => [formatEventName(e)]); 

        const infoSheetAOA = [
            ['PETUNJUK PENGISIAN NOMOR LOMBA'],
            ["Salin (copy) nama nomor lomba dari kolom A, lalu tempel (paste) ke kolom 'Nomor Lomba' di sheet 'Template Pendaftaran'."],
            ["Pastikan nama nomor lomba sesuai persis dengan yang ada di daftar ini."],
            [], // Spacer
            ['DAFTAR LOMBA YANG TERSEDIA', '', 'DAFTAR KATEGORI UMUR (KU)'],
        ];

        // Combine events list with KU list side-by-side
        const maxLength = Math.max(allEventsFormatted.length, ageOptions.length);
        const dataRows = [];

        for (let i = 0; i < maxLength; i++) {
            const eventName = allEventsFormatted[i] ? allEventsFormatted[i][0] : "";
            const ageGroupName = ageOptions[i] || "";
            dataRows.push([eventName, "", ageGroupName]);
        }

        const fullInfoSheetAOA = infoSheetAOA.concat(dataRows);

        const wsInfo = XLSX.utils.aoa_to_sheet(fullInfoSheetAOA);
        wsInfo['!cols'] = [ { wch: 70 }, { wch: 5 }, { wch: 30 } ];

        // Merges for header text
        wsInfo['!merges'] = [
            { s: { r: 0, c: 0 }, e: { r: 0, c: 2 } },
            { s: { r: 1, c: 0 }, e: { r: 1, c: 2 } },
            { s: { r: 2, c: 0 }, e: { r: 2, c: 2 } },
        ];

        XLSX.utils.book_append_sheet(workbook, wsInfo, "Daftar Nomor Lomba");

        // --- Write File ---
        XLSX.writeFile(workbook, "Template_Pendaftaran_Lomba.xlsx");

    } catch(error) {
        console.error("Failed to generate template:", error);
        alert("Gagal membuat template. Silakan coba lagi.");
    } finally {
        setIsDownloading(false);
    }
  };

  const handleDownloadParticipants = () => {
    if (typeof XLSX === 'undefined') {
      alert('Pustaka untuk membuat file Excel belum termuat. Periksa koneksi internet Anda dan muat ulang halaman.');
      return;
    }

    if (swimmers.length === 0) {
      alert('Tidak ada data atlet untuk diunduh.');
      return;
    }

    const workbook = XLSX.utils.book_new();

    // --- Sheet 1: Rekap Atlet ---
    const sortedSwimmers = [...swimmers].sort((a, b) => a.name.localeCompare(b.name));
    const participantsData = sortedSwimmers.map((swimmer, index) => ({
      "No": index + 1,
      "Nama Atlet": swimmer.name,
      "Nama Tim": swimmer.club,
      "Jenis Kelamin (L/P)": swimmer.gender === 'Male' ? 'L' : 'P'
    }));
    const wsParticipants = XLSX.utils.json_to_sheet(participantsData, { skipHeader: false });
    wsParticipants['!cols'] = [
        { wch: 5 },
        { wch: 40 },
        { wch: 35 },
        { wch: 20 }
    ];

    const totalMale = swimmers.filter(s => s.gender === 'Male').length;
    const totalFemale = swimmers.filter(s => s.gender === 'Female').length;
    XLSX.utils.sheet_add_aoa(wsParticipants, [
        [], // Spacer row
        ["REKAPITULASI JUMLAH ATLET"],
        ["Total Putra (L)", totalMale],
        ["Total Putri (P)", totalFemale],
        ["Total Keseluruhan", swimmers.length]
    ], { origin: -1 });
    const summaryHeaderRowIndex = participantsData.length + 2;
    if (!wsParticipants['!merges']) wsParticipants['!merges'] = [];
    wsParticipants['!merges'].push({ s: { r: summaryHeaderRowIndex, c: 0 }, e: { r: summaryHeaderRowIndex, c: 1 } });
    XLSX.utils.book_append_sheet(workbook, wsParticipants, "Rekap Atlet");

    // --- Sheet 2: Rekap Tim ---
    const clubRecap: Record<string, { male: number; female: number }> = {};
    swimmers.forEach(swimmer => {
      if (!clubRecap[swimmer.club]) {
        clubRecap[swimmer.club] = { male: 0, female: 0 };
      }
      if (swimmer.gender === 'Male') {
        clubRecap[swimmer.club].male++;
      } else {
        clubRecap[swimmer.club].female++;
      }
    });

    const sortedClubs = Object.entries(clubRecap).sort((a, b) => a[0].localeCompare(b[0]));
    const clubsData = sortedClubs.map(([clubName, counts], index) => ({
      "No": index + 1,
      "Nama Tim": clubName,
      "Jumlah Putra (L)": counts.male,
      "Jumlah Putri (P)": counts.female,
      "Total Atlet": counts.male + counts.female
    }));
    const wsClubs = XLSX.utils.json_to_sheet(clubsData, { skipHeader: false });
    wsClubs['!cols'] = [
        { wch: 5 },
        { wch: 40 },
        { wch: 20 },
        { wch: 20 },
        { wch: 20 }
    ];

    const grandTotalMale = sortedClubs.reduce((acc, [, counts]) => acc + counts.male, 0);
    const grandTotalFemale = sortedClubs.reduce((acc, [, counts]) => acc + counts.female, 0);
    const grandTotal = grandTotalMale + grandTotalFemale;

    XLSX.utils.sheet_add_aoa(wsClubs, [
        [], // Spacer row
        ["", "TOTAL KESELURUHAN", grandTotalMale, grandTotalFemale, grandTotal]
    ], { origin: -1 });

    XLSX.utils.book_append_sheet(workbook, wsClubs, "Rekap Tim");

    XLSX.writeFile(workbook, "Rekap_Peserta_Kompetisi.xlsx");
  };

  const handleDownloadFullRegistration = () => {
    if (typeof XLSX === 'undefined') {
        alert('Pustaka untuk membuat file Excel belum termuat. Periksa koneksi internet Anda dan muat ulang halaman.');
        return;
    }

    if (events.length === 0) {
        alert('Tidak ada data pendaftaran untuk diunduh.');
        return;
    }

    setIsDownloading(true);

    try {
        const dataToExport = [];
        // FIX: Explicitly typed the Map to ensure correct type inference for the swimmer object.
        const swimmersMap = new Map<string, Swimmer>(swimmers.map(s => [s.id, s]));

        for (const event of events) {
            for (const entry of event.entries) {
                const swimmer: Swimmer | undefined = swimmersMap.get(entry.swimmerId);
                if (swimmer) {
                    dataToExport.push({
                        "Nama Atlet": swimmer.name,
                        "Jenis Kelamin": swimmer.gender === 'Male' ? 'L' : 'P',
                        "Tahun Lahir": swimmer.birthYear,
                        "Nama Tim": swimmer.club,
                        "Nomor Lomba": formatEventName(event),
                        "Waktu Unggulan": formatTime(entry.seedTime)
                    });
                }
            }
        }

        dataToExport.sort((a, b) => {
            const clubCompare = a["Nama Tim"].localeCompare(b["Nama Tim"]);
            if (clubCompare !== 0) return clubCompare;
            const nameCompare = a["Nama Atlet"].localeCompare(b["Nama Atlet"]);
            if (nameCompare !== 0) return nameCompare;
            return a["Nomor Lomba"].localeCompare(b["Nomor Lomba"]);
        });

        const worksheet = XLSX.utils.json_to_sheet(dataToExport);
        worksheet['!cols'] = [ { wch: 30 }, { wch: 15 }, { wch: 15 }, { wch: 30 }, { wch: 45 }, { wch: 20 }];

        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, "Rekap Pendaftaran Lengkap");
        XLSX.writeFile(workbook, "Rekap_Pendaftaran_Lengkap.xlsx");
    } catch (error) {
        console.error("Failed to generate full registration report:", error);
        alert("Gagal membuat laporan pendaftaran. Silakan coba lagi.");
    } finally {
        setIsDownloading(false);
    }
  };


  // --- Manual Registration Logic ---
  const handleManualFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setManualForm(prev => ({ ...prev, [name]: value }));
  };

  const availableCategories = useMemo(() => {
    const categories = new Set(events.map(e => e.category || 'Tanpa Kategori'));
    return Array.from(categories).sort();
  }, [events]);

  const availableEventsForManualReg = useMemo(() => {
      if (!manualForm.swimmerId) return [];
      const swimmer = swimmers.find(s => s.id === manualForm.swimmerId);
      if (!swimmer) return [];

      const registeredEventIds = new Set<string>(
          events.filter(e => e.entries.some(en => en.swimmerId === swimmer.id)).map(e => e.id)
      );

      return events.filter(event => {
          const genderMatch =
              event.gender === 'Mixed' ||
              (swimmer.gender === 'Male' && event.gender === "Men's") ||
              (swimmer.gender === 'Female' && event.gender === "Women's");

          const categoryMatch = categoryFilter === 'all' || (event.category || 'Tanpa Kategori') === categoryFilter;

          return !registeredEventIds.has(event.id) && genderMatch && categoryMatch;
      });
  }, [manualForm.swimmerId, swimmers, events, categoryFilter]);

  const handleManualRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualForm.swimmerId || !manualForm.eventId) {
        addNotification('Silakan pilih atlet dan nomor lomba.', 'error');
        return;
    }

    const min = parseInt(manualForm.min || '0');
    const sec = parseInt(manualForm.sec || '0');
    const ms = parseInt(manualForm.ms || '0');

    if (sec >= 60 && !(min === 99 && sec === 99 && ms === 99)) {
        addNotification('Input detik harus di bawah 60, kecuali untuk "No Time" (99:99.99).', 'error');
        return;
    }

    setIsProcessing(true);
    let seedTime = (min * 60000) + (sec * 1000) + (ms * 10);
    if (min === 99 && sec === 99 && ms === 99) {
        seedTime = 0;
    }

    try {
        const result = await registerSwimmerToEvent(manualForm.eventId, manualForm.swimmerId, seedTime);
        if (result.success) {
            addNotification('Pendaftaran berhasil ditambahkan!', 'success');
            setManualForm({ swimmerId: '', eventId: '', min: '99', sec: '99', ms: '99' });
            onUploadSuccess(); // Refresh all data
        } else {
            addNotification(result.message, 'error');
        }
    } catch (err: any) {
        addNotification(`Gagal mendaftar: ${err.message}`, 'error');
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div>
      <h1 className="text-3xl font-bold mb-6">Manajemen Peserta</h1>
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card>
          <h2 className="text-xl font-bold mb-4">Pendaftaran Manual</h2>
          <form onSubmit={handleManualRegister} className="space-y-4">
            <Select label="Pilih Atlet" id="manual-swimmer" name="swimmerId" value={manualForm.swimmerId} onChange={handleManualFormChange}>
                <option value="">-- Pilih Atlet --</option>
                {swimmers.sort((a,b) => a.name.localeCompare(b.name)).map(s => <option key={s.id} value={s.id}>{s.name} ({s.club})</option>)}
            </Select>
            <Select
                label="Filter berdasarkan Kategori"
                id="manual-category-filter"
                value={categoryFilter}
                onChange={(e) => {
                    setCategoryFilter(e.target.value);
                    setManualForm(prev => ({ ...prev, eventId: '' })); // Reset event selection
                }}
                disabled={!manualForm.swimmerId}
            >
                <option value="all">Semua Kategori</option>
                {availableCategories.map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                ))}
            </Select>
            <Select 
              label="Pilih Nomor Lomba" 
              id="manual-event" 
              name="eventId" 
              value={manualForm.eventId} 
              onChange={handleManualFormChange} 
              disabled={!manualForm.swimmerId || availableEventsForManualReg.length === 0}
            >
                <option value="">-- Pilih Nomor Lomba --</option>
                {availableEventsForManualReg.map(e => <option key={e.id} value={e.id}>{formatEventName(e)}</option>)}
            </Select>
             <div>
                <label className="block text-sm font-medium text-text-secondary mb-1">Waktu Unggulan</label>
                <div className="grid grid-cols-3 gap-2">
                    <Input label="Menit" id="manual-min" name="min" type="number" min="0" value={manualForm.min} onChange={handleManualFormChange} />
                    <Input label="Detik" id="manual-sec" name="sec" type="number" min="0" max="99" value={manualForm.sec} onChange={handleManualFormChange} />
                    <Input label="ss/100" id="manual-ms" name="ms" type="number" min="0" max="99" value={manualForm.ms} onChange={handleManualFormChange} />
                </div>
            </div>
            <div className="pt-2">
                <Button type="submit" className="w-full" disabled={isProcessing}>
                    {isProcessing ? <Spinner/> : 'Daftarkan Atlet'}
                </Button>
            </div>
          </form>
        </Card>

        <Card>
          <h2 className="text-xl font-bold mb-4">Pendaftaran Massal via Excel</h2>
          <div className="bg-background p-4 rounded-md border border-border space-y-3 mb-4">
              <div>
                <p className="text-text-secondary">Unggah file Excel (.xlsx) dengan kolom berikut untuk mendaftarkan peserta ke nomor lomba:</p>
                <code className="block text-sm bg-surface p-2 rounded-md whitespace-pre mt-1">Nama Atlet | Tahun Lahir | Jenis Kelamin (L/P) | Nama Tim | KU | Nomor Lomba | Waktu Unggulan (mm:ss.SS)</code>
              </div>
              <div className="flex flex-wrap gap-2">
                  <Button variant="secondary" onClick={downloadTemplate} disabled={isDownloading || !canDownload} title={!canDownload ? "Buat 'Nomor Lomba' terlebih dahulu untuk mengunduh template" : "Unduh template Excel dengan daftar nomor lomba dan KU"}>
                      {isDownloading ? <Spinner /> : 'Unduh Template Pendaftaran'}
                  </Button>
                  <Button variant="secondary" onClick={handleDownloadParticipants} disabled={swimmers.length === 0} title={swimmers.length === 0 ? "Tidak ada atlet untuk diunduh" : "Unduh rekap semua atlet"}>
                      Unduh Rekap Atlet
                  </Button>
                   <Button variant="secondary" onClick={handleDownloadFullRegistration} disabled={isDownloading || events.length === 0 || swimmers.length === 0} title="Unduh rekap lengkap semua pendaftaran per nomor lomba">
                      {isDownloading ? <Spinner /> : 'Unduh Rekap Pendaftaran Lengkap'}
                    </Button>
              </div>
              <p className="text-xs text-text-secondary">{canDownload ? "Template Pendaftaran akan berisi daftar nomor lomba dan KU yang telah dibuat." : "Tombol 'Unduh Template Pendaftaran' akan aktif setelah Anda membuat setidaknya satu nomor lomba."}</p>
          </div>

          <div className="flex items-center space-x-4">
              <input type="file" id="participant-upload" accept=".xlsx, .xls" className="hidden" onChange={handleFileChange} />
              <Button type="button" onClick={() => document.getElementById('participant-upload')?.click()}>Pilih File Pendaftaran</Button>
              {file && <span className="text-text-secondary">{file.name}</span>}
          </div>

          <div className="mt-4"><Button onClick={handleUpload} disabled={!file || isProcessing}>{isProcessing ? <Spinner/> : 'Proses File Pendaftaran'}</Button></div>

          {uploadResult && (
              <div className="mt-6 pt-4 border-t border-border">
                  <h3 className="font-bold text-lg">Hasil Impor:</h3>
                  {(uploadResult.newSwimmers > 0 || uploadResult.updatedSwimmers > 0) && (
                      <div className="text-green-400 space-y-1 my-2"><p><strong>Total entri lomba berhasil diproses: {uploadResult.updatedSwimmers}</strong></p>
                      {uploadResult.newSwimmers > 0 && <p className="text-sm pl-2">({uploadResult.newSwimmers} atlet/tim baru ditambahkan ke database)</p>}
                      </div>
                  )}
                  {uploadResult.errors.length > 0 && (
                      <div className="mt-2"><p className="text-red-500">{uploadResult.errors.length} baris gagal diproses:</p><ul className="list-disc list-inside text-red-500 text-sm h-32 overflow-y-auto bg-surface p-2 rounded-md mt-1">{uploadResult.errors.map((err, i) => <li key={i}>{err}</li>)}</ul></div>
                  )}
                  {uploadResult.newSwimmers === 0 && uploadResult.updatedSwimmers === 0 && uploadResult.errors.length === 0 && (<p className="text-text-secondary">Tidak ada data baru yang ditambahkan dari file.</p>)}
              </div>
          )}
        </Card>
      </div>
    </div>
  );
};

import { createClient } from '@supabase/supabase-js';

const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_SERVICE_KEY = process.env.SUPABASE_SERVICE_KEY;

let supabaseAdmin;
if (SUPABASE_URL && SUPABASE_SERVICE_KEY) {
  supabaseAdmin = createClient(SUPABASE_URL, SUPABASE_SERVICE_KEY);
}

// Helper functions to map DB schema to app types (camelCase)
const toCompetitionInfo = (data) => (data ? {
    eventName: data.event_name,
    eventDate: data.event_date,
    eventLogo: data.event_logo,
    sponsorLogo: data.sponsor_logo,
    isRegistrationOpen: data.is_registration_open,
    numberOfLanes: data.number_of_lanes,
    registrationDeadline: data.registration_deadline,
    ageGroups: data.age_groups // Added missing field
} : null);

const toSwimmer = (data) => ({
    id: data.id,
    name: data.name,
    birthYear: data.birth_year,
    gender: data.gender,
    club: data.club,
    ageGroup: data.age_group,
});

const toEventEntry = (data) => ({
    swimmerId: data.swimmer_id,
    seedTime: data.seed_time
});

const toResult = (data) => ({
    swimmerId: data.swimmer_id,
    time: data.time
});

const toSwimEvent = (data) => ({
    id: data.id,
    distance: data.distance,
    style: data.style,
    gender: data.gender,
    sessionNumber: data.session_number,
    heatOrder: data.heat_order,
    sessionDateTime: data.session_date_time,
    relayLegs: data.relay_legs,
    category: data.category,
    entries: data.event_entries?.map(toEventEntry) || [],
    results: data.event_results?.map(toResult) || []
});

const toRecord = (data) => ({
    id: data.id,
    type: data.type,
    gender: data.gender,
    distance: data.distance,
    style: data.style,
    time: data.time,
    holderName: data.holder_name,
    yearSet: data.year_set,
    locationSet: data.location_set,
    relayLegs: data.relay_legs,
    category: data.category
});

export const handler = async (event) => {
    if (event.httpMethod !== 'GET') {
        return { statusCode: 405, body: JSON.stringify({ message: 'Method Not Allowed' }) };
    }
    if (!supabaseAdmin) {
        return { statusCode: 500, body: JSON.stringify({ message: 'Database configuration error on server.' }) };
    }

    try {
        const [infoRes, swimmersRes, eventsRes, recordsRes] = await Promise.all([
            supabaseAdmin.from('competition_info').select('*').eq('id', 1).single(),
            supabaseAdmin.from('swimmers').select('*'),
            supabaseAdmin.from('events').select('*, event_entries(*), event_results(*)').order('session_number').order('heat_order'),
            supabaseAdmin.from('records').select('*')
        ]);

        if (infoRes.error && infoRes.error.code !== 'PGRST116') throw infoRes.error; // Ignore "No rows found" for info
        if (swimmersRes.error) throw swimmersRes.error;
        if (eventsRes.error) throw eventsRes.error;
        if (recordsRes.error) throw recordsRes.error;

        const competitionInfo = toCompetitionInfo(infoRes.data);
        const swimmers = swimmersRes.data.map(toSwimmer);
        const events = eventsRes.data.map(toSwimEvent);
        const records = recordsRes.data.map(toRecord);

        return {
            statusCode: 200,
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ competitionInfo, swimmers, events, records }),
        };
    } catch (error) {
        console.error("Error in getPublicData function:", error.message || error);
        return {
            statusCode: 500,
            body: JSON.stringify({ message: `Server error: ${error.message || 'Unknown database error.'}` })
        };
    }
};

import { supabase } from './supabaseClient';
import type { User } from '../types';
import { config } from '../config';

const AUTH_KEY = 'swimcomp_auth_user';

export const login = async (email?: string, password?: string): Promise<User | null> => {
  if (!email || !password) {
      throw new Error("Email dan kata sandi wajib diisi.");
  }

  // Step 1: Check for Super Admin credentials from config file.
  if (email === config.superAdmin.email && password === config.superAdmin.password) {
    const superAdminUser: User = {
      id: 'super-admin-local', // Static ID for the local super admin
      role: 'SUPER_ADMIN',
      email: config.superAdmin.email,
      app_metadata: { provider: 'local' },
      user_metadata: { full_name: 'Super Admin' },
      aud: 'authenticated',
      created_at: new Date().toISOString(),
    };
    sessionStorage.setItem(AUTH_KEY, JSON.stringify(superAdminUser));
    return superAdminUser;
  }

  // Step 2: If not super admin, proceed with Supabase authentication for regular admins.
  // FIX: Replaced `signIn` with `signInWithPassword` for compatibility with Supabase JS v2, and adjusted destructuring.
  // Using (supabase.auth as any) to bypass potential type definition mismatches if v1 types are installed but v2 logic is used.
  const { data: authSession, error: authError } = await (supabase.auth as any).signInWithPassword({
    email: email,
    password: password,
  });
  const authUser = authSession?.user;


  if (authError || !authUser) {
    if (authError) {
      console.error("Supabase Auth sign-in failed:", authError.name, authError.message);

      // Check for the generic invalid credentials error first.
      // This is what Supabase returns for both wrong passwords and unconfirmed emails during sign-in
      // to avoid leaking information about which emails are registered.
      if (authError.message.includes("Invalid login credentials")) {
        throw new Error("Login Gagal: Kredensial tidak valid. PENYEBAB PALING UMUM: Jika ini akun Admin baru, Anda harus menonaktifkan 'Confirm email' di pengaturan Authentication Supabase Anda. Lihat petunjuk di README. Jika sudah, periksa kembali email dan kata sandi.");
      }

      // Check for a more specific email confirmation error, which might be returned in other scenarios.
      if (authError.message.includes("Email not confirmed")) {
        throw new Error("Email untuk akun ini belum dikonfirmasi. Silakan periksa kotak masuk email Anda.");
      }

      // For any other specific auth errors, throw the original message.
      throw new Error(authError.message);

    } else {
      // This case handles when Supabase returns no user and no error, which is unexpected.
      console.error("Supabase Auth sign-in failed: No user data returned without an explicit error.");
      throw new Error("Login gagal karena respons tak terduga dari server otentikasi.");
    }
  }

  // Step 3: Now that the user is authenticated, fetch their role from our public.users table.
  const { data: profileData, error: profileError } = await supabase
    .from('users')
    .select('role')
    .eq('id', authUser.id)
    .single();

  if (profileError || !profileData) {
    console.error("Failed to fetch user profile/role after login:", profileError?.message);
    // This is a critical error. The user exists in Auth but not in our profiles table.
    // It's crucial to log them out to prevent a broken state.
    // FIX: Replaced `logout` with `signOut` for compatibility with Supabase JS v2.
    // Using (supabase.auth as any) to bypass potential type definition mismatches.
    const { error: signOutError } = await (supabase.auth as any).signOut();
    if (signOutError) {
        // Log the sign-out error but proceed to throw the main profile error.
        console.error("Sign out failed after profile error:", signOutError.message);
    }
    throw new Error("Profil pengguna tidak ditemukan. Hubungi administrator.");
  }

  // Step 4: Combine the auth user and profile data into our app's User type.
  const finalUser: User = {
    ...authUser,
    role: (profileData as { role: 'SUPER_ADMIN' | 'ADMIN' }).role,
  };

  sessionStorage.setItem(AUTH_KEY, JSON.stringify(finalUser));
  return finalUser;
};

export const logout = async (): Promise<void> => {
  sessionStorage.removeItem(AUTH_KEY);
  // FIX: Replaced `logout` with `signOut` for compatibility with Supabase JS v2.
  // Using (supabase.auth as any) to bypass potential type definition mismatches.
  const { error } = await (supabase.auth as any).signOut();
  if (error) {
    console.error("Error logging out:", error.message);
  }
};

export const getCurrentUser = (): User | null => {
  const data = sessionStorage.getItem(AUTH_KEY);
  try {
    const user = data ? JSON.parse(data) : null;
    return user;
  } catch (error) {
    console.error("Failed to parse user from session storage", error);
    return null;
  }
};

export const isLoggedIn = (): boolean => {
  return getCurrentUser() !== null;
};

import React, { useState, useMemo, useEffect } from 'react';
import type { CompetitionInfo, SwimEvent, Swimmer, FormattableEvent } from '../types';
import { getEventsForRegistration, processOnlineRegistration, findSwimmerByName } from '../services/databaseService';
import { Card } from './ui/Card';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { Select } from './ui/Select';
import { Spinner } from './ui/Spinner';
import { formatEventName, toTitleCase, formatTime, translateSwimStyle, AGE_GROUP_OPTIONS } from '../constants';
import { SwimStyle, Gender } from '../types';

interface OnlineRegistrationViewProps {
    competitionInfo: CompetitionInfo | null;
    onBackToLogin: () => void;
    onRegistrationSuccess: () => void;
}

type RegistrationTime = { min: string; sec: string; ms: string };
type SelectedEvents = Record<string, { selected: boolean; time: RegistrationTime }>;

interface OnlineRegistrationResponse {
    success: boolean;
    message: string;
    swimmer: Swimmer | null;
    previouslyRegisteredEvents?: FormattableEvent[];
}

const parseTimeToMs = (time: RegistrationTime): number => {
    const minutes = parseInt(time.min, 10) || 0;
    const seconds = parseInt(time.sec, 10) || 0;
    const hundredths = parseInt(time.ms, 10) || 0;
    if (minutes === 99 && seconds === 99 && hundredths === 99) {
        return 0; // Treat as No Time
    }
    return (minutes * 60 * 1000) + (seconds * 1000) + (hundredths * 10);
};

const ChevronDownIcon = ({ isOpen }: { isOpen: boolean }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={`h-6 w-6 transform transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
    </svg>
);


export const OnlineRegistrationView: React.FC<OnlineRegistrationViewProps> = ({
    competitionInfo,
    onBackToLogin,
    onRegistrationSuccess,
}) => {
    const [localEvents, setLocalEvents] = useState<SwimEvent[]>([]);
    const [isDataLoading, setIsDataLoading] = useState(true);
    const [formData, setFormData] = useState({
        name: '',
        birthYear: new Date().getFullYear() - 10,
        gender: 'Male' as 'Male' | 'Female',
        club: '',
        ageGroup: '',
    });
    const [selectedEvents, setSelectedEvents] = useState<SelectedEvents>({});
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState('');
    const [successMessage, setSuccessMessage] = useState('');

    // State for auto-fill feature
    const [isCheckingName, setIsCheckingName] = useState(false);
    const [existingSwimmer, setExistingSwimmer] = useState<Swimmer | null>(null);

    // State for deadline countdown
    const [timeLeft, setTimeLeft] = useState('');
    const [isDeadlinePassed, setIsDeadlinePassed] = useState(false);

    // State for accordion
    const [openAccordion, setOpenAccordion] = useState<SwimStyle | null>(null);

    // Dynamic Age Groups Logic
    const ageOptions = useMemo(() => {
        if (competitionInfo?.ageGroups) {
            return competitionInfo.ageGroups.split('\n').map(s => s.trim()).filter(Boolean);
        }
        return AGE_GROUP_OPTIONS;
    }, [competitionInfo]);

    useEffect(() => {
        const fetchEvents = async () => {
            setIsDataLoading(true);
            const onlineEvents = await getEventsForRegistration();
            setLocalEvents(onlineEvents);
            setIsDataLoading(false);
        };

        fetchEvents();
    }, []);

    useEffect(() => {
        if (!competitionInfo?.registrationDeadline) {
            setIsDeadlinePassed(false);
            setTimeLeft('');
            return;
        }

        const deadline = new Date(competitionInfo.registrationDeadline);

        const updateCountdown = () => {
            const now = new Date();
            const difference = deadline.getTime() - now.getTime();

            if (difference <= 0) {
                setIsDeadlinePassed(true);
                setTimeLeft('Batas waktu pendaftaran telah berakhir.');
                if (intervalId) clearInterval(intervalId);
                return;
            }

            const days = Math.floor(difference / (1000 * 60 * 60 * 24));
            const hours = Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
            const minutes = Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60));
            const seconds = Math.floor((difference % (1000 * 60)) / 1000);

            setTimeLeft(`${days} hari ${hours} jam ${minutes} menit ${seconds} detik`);
        };

        updateCountdown();
        const intervalId = setInterval(updateCountdown, 1000);

        return () => clearInterval(intervalId);
    }, [competitionInfo?.registrationDeadline]);

    const handleAccordionToggle = (style: SwimStyle) => {
        setOpenAccordion(prev => (prev === style ? null : style));
    };

    const isFormValid = useMemo(() => {
        const hasPersonalInfo = formData.name.trim() !== '' && formData.club.trim() !== '';
        // FIX: Explicitly type `e` to resolve 'unknown' type error.
        const hasSelectedEvent = Object.values(selectedEvents).some((e: { selected: boolean; }) => e.selected);
        return hasPersonalInfo && hasSelectedEvent;
    }, [formData, selectedEvents]);

    const availableEvents = useMemo(() => {
        const registeredEventIds = new Set<string>();
        if (existingSwimmer) {
            localEvents.forEach(event => {
                if (event.entries.some(entry => entry.swimmerId === existingSwimmer.id)) {
                    registeredEventIds.add(event.id);
                }
            });
        }

        return localEvents
            .filter((event: SwimEvent) => {
                if (registeredEventIds.has(event.id)) return false;
                return event.gender === "Mixed" || (formData.gender === "Male" && event.gender === "Men's") || (formData.gender === "Female" && event.gender === "Women's");
            })
            .sort((a,b) => a.distance - b.distance || a.style.localeCompare(b.style));
    }, [localEvents, formData.gender, existingSwimmer]);

    const groupedAvailableEvents = useMemo(() => {
        return availableEvents.reduce((acc: Record<SwimStyle, SwimEvent[]>, event: SwimEvent) => {
            const style = event.style;
            if (!acc[style]) {
                acc[style] = [];
            }
            acc[style].push(event);
            return acc;
        }, {} as Record<SwimStyle, SwimEvent[]>);
    }, [availableEvents]);

    const selectedEventCount = useMemo(() => {
        return Object.values(selectedEvents).filter((e: { selected: boolean }) => e.selected).length;
    }, [selectedEvents]);

    // Calculate a summary of selected events for the review card
    const selectedEventsSummary = useMemo(() => {
        return Object.entries(selectedEvents)
            .filter(([_, val]) => val.selected)
            .map(([eventId, val]) => {
                const event = localEvents.find(e => e.id === eventId);
                if (!event) return null;

                // Format display time
                let timeStr = 'NT';
                const min = val.time.min || '0';
                const sec = val.time.sec || '0';
                const ms = val.time.ms || '0';

                if (min === '99' && sec === '99' && ms === '99') {
                    timeStr = 'NT';
                } else {
                    timeStr = `${min.padStart(2, '0')}:${sec.padStart(2, '0')}.${ms.padStart(2, '0')}`;
                }

                return { event, timeStr };
            })
            .filter((item): item is { event: SwimEvent, timeStr: string } => item !== null)
            .sort((a, b) => {
                // Sort summary by style then distance
                const styleCompare = a.event.style.localeCompare(b.event.style);
                if (styleCompare !== 0) return styleCompare;
                return a.event.distance - b.event.distance;
            });
    }, [selectedEvents, localEvents]);


    const handleFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        let finalValue: string | number = value;

        if (name === 'birthYear') {
            finalValue = parseInt(value);
        } else if (name === 'name' || name === 'club') {
            finalValue = toTitleCase(value);
        }

        setFormData(prev => ({ ...prev, [name]: finalValue }));
        setError('');
        setSuccessMessage('');
    };

    const handleEventSelectionChange = (eventId: string) => {
        setSelectedEvents(prev => ({
            ...prev,
            [eventId]: {
                selected: !prev[eventId]?.selected,
                time: prev[eventId]?.time || { min: '99', sec: '99', ms: '99' },
            },
        }));
    };

    const handleTimeChange = (eventId: string, part: keyof RegistrationTime, value: string) => {
        setSelectedEvents(prev => {
            const currentEvent = prev[eventId] || { selected: true, time: { min: '99', sec: '99', ms: '99' } };
            return {
                ...prev,
                [eventId]: {
                    ...currentEvent,
                    time: { ...currentEvent.time, [part]: value },
                },
            };
        });
    };

    const handleSetNoTime = (eventId: string) => {
        handleTimeChange(eventId, 'min', '99');
        handleTimeChange(eventId, 'sec', '99');
        handleTimeChange(eventId, 'ms', '99');
    };

    const handleNameBlur = async (e: React.FocusEvent<HTMLInputElement>) => {
        const swimmerName = e.target.value.trim();
        if (swimmerName.length < 3) {
            if (existingSwimmer) {
                setExistingSwimmer(null);
                setFormData(prev => ({ ...prev, club: '', birthYear: new Date().getFullYear() - 10, gender: 'Male', ageGroup: '' }));
            }
            return;
        }
        setIsCheckingName(true);
        const foundSwimmer = await findSwimmerByName(swimmerName);
        setIsCheckingName(false);
        if (foundSwimmer) {
            setFormData({
                name: foundSwimmer.name,
                club: foundSwimmer.club,
                birthYear: foundSwimmer.birthYear,
                gender: foundSwimmer.gender,
                ageGroup: foundSwimmer.ageGroup || '',
            });
            setExistingSwimmer(foundSwimmer);
        } else if (existingSwimmer) {
            clearAutoFilledData();
        }
    };

    const clearAutoFilledData = () => {
        setExistingSwimmer(null);
        setFormData(prev => ({ ...prev, club: '', birthYear: new Date().getFullYear() - 10, gender: 'Male', ageGroup: '' }));
        setTimeout(() => document.getElementById('club')?.focus(), 0);
    };


    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setSuccessMessage('');
        setIsSubmitting(true);

        if (!formData.name.trim() || !formData.club.trim()) {
            setError('Nama atlet dan nama tim wajib diisi.');
            setIsSubmitting(false);
            return;
        }

        const registrationsToSubmit = [];
        for (const [eventId, val] of Object.entries(selectedEvents)) {
            const eventValue = val as { selected: boolean; time: RegistrationTime };
            if (eventValue.selected) {
                const min = parseInt(eventValue.time.min, 10) || 0;
                const sec = parseInt(eventValue.time.sec, 10) || 0;
                const ms = parseInt(eventValue.time.ms, 10) || 0;

                if (sec >= 60 && !(min === 99 && sec === 99 && ms === 99)) {
                    const eventDetails = availableEvents.find(e => e.id === eventId);
                    const eventName = eventDetails ? formatEventName(eventDetails) : `nomor lomba ID ${eventId}`;
                    setError(`Error pada ${eventName}: Input detik harus di bawah 60.`);
                    setIsSubmitting(false);
                    return;
                }

                registrationsToSubmit.push({
                    eventId,
                    seedTime: parseTimeToMs(eventValue.time),
                });
            }
        }

        if (registrationsToSubmit.length === 0) {
            setError('Anda harus memilih setidaknya satu nomor lomba.');
            setIsSubmitting(false);
            return;
        }

        const result: OnlineRegistrationResponse = await processOnlineRegistration(formData, registrationsToSubmit);
        setIsSubmitting(false);

        if (result.success && result.swimmer) {
            const swimmerName = result.swimmer.name;

            // Newly registered events formatted with their seed time
            const newlyRegisteredEventsList = registrationsToSubmit.map(reg => {
                const event = localEvents.find(e => e.id === reg.eventId);
                const eventName = event ? formatEventName(event) : 'Nomor Lomba Tidak Dikenal';
                const time = formatTime(reg.seedTime);
                return `• ${eventName} (Waktu: ${time})`;
            });

            // Previously registered events (without seed time, as we don't have it easily)
            const eventsFromServer = ((result.previouslyRegisteredEvents || []) as any[]);
            const previouslyRegisteredEventsList = eventsFromServer.map((event: any) => {
                const formattableEvent: FormattableEvent = {
                    distance: event.distance,
                    style: event.style,
                    gender: event.gender,
                    relayLegs: event.relay_legs, // Use snake_case from server
                    category: event.category,
                };
                return `• ${formatEventName(formattableEvent)}`;
            });

            // Combine all event strings and sort them for a clean list
            const allRegisteredEventsString = [
                ...newlyRegisteredEventsList,
                ...previouslyRegisteredEventsList,
            ].sort().join('\n');

            const successText = (
                <div className="text-left">
                    <p className="font-bold text-lg mb-2">Pendaftaran untuk {swimmerName} berhasil!</p>
                    <p className="mb-2">Anda sekarang terdaftar di nomor lomba berikut:</p>
                    <pre className="bg-background p-2 rounded-md text-sm whitespace-pre-wrap max-h-60 overflow-y-auto">
                        {allRegisteredEventsString}
                    </pre>
                </div>
            );

            setSuccessMessage(successText as any); // Cast to any to allow ReactNode
            onRegistrationSuccess();

            // Reset form for next entry
            setFormData({
                name: '',
                birthYear: new Date().getFullYear() - 10,
                gender: 'Male',
                club: '',
                ageGroup: '',
            });
            setSelectedEvents({});
            setExistingSwimmer(null);

        } else {
            setError(result.message || 'Terjadi kesalahan yang tidak diketahui.');
        }
    };

    const isRegistrationDisabled = isDeadlinePassed || !competitionInfo?.isRegistrationOpen;

    if (isDataLoading) {
        return (
            <div className="min-h-screen bg-background flex flex-col items-center justify-center p-4">
                <Spinner />
                <p className="text-text-secondary mt-4">Memuat data kompetisi...</p>
            </div>
        );
    }

     if (isRegistrationDisabled && !isDataLoading) {
        return (
             <div className="min-h-screen bg-gradient-to-br from-gray-100 to-slate-200 dark:from-slate-800 dark:to-gray-900 flex flex-col items-center justify-center p-4 text-center">
                <Card className="max-w-xl">
                    <h1 className="text-2xl font-bold text-primary mb-4">{competitionInfo?.eventName.split('\n')[0]}</h1>
                    <p className="text-lg text-red-500 font-semibold mb-2">Pendaftaran Online Saat Ini Ditutup</p>
                    <p className="text-text-secondary mb-6">
                        {timeLeft || 'Pendaftaran untuk kompetisi ini belum dibuka atau sudah berakhir. Silakan hubungi panitia untuk informasi lebih lanjut.'}
                    </p>
                    <Button onClick={onBackToLogin}>Kembali ke Halaman Utama</Button>
                </Card>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gradient-to-br from-sky-100 to-blue-200 dark:from-slate-800 dark:to-sky-900 flex flex-col items-center p-4">
            <div className="w-full max-w-4xl mx-auto">
                 <header className="text-center py-6">
                    {competitionInfo?.eventLogo && <img src={competitionInfo.eventLogo} alt="Logo Acara" className="mx-auto h-20 md:h-24 object-contain mb-4" />}
                    {competitionInfo && (
                        <div>
                            <h1 className="text-3xl md:text-5xl font-extrabold text-primary tracking-tight">{competitionInfo.eventName.split('\n')[0]}</h1>
                            <h2 className="text-xl md:text-2xl font-semibold text-text-secondary tracking-wide mt-1">{competitionInfo.eventName.split('\n')[1]}</h2>
                        </div>
                    )}
                    <h3 className="text-2xl font-bold text-text-primary mt-4">Formulir Pendaftaran Online</h3>
                </header>

                {timeLeft && (
                    <Card className="text-center mb-4 border-primary/50 bg-primary/5">
                        <p className="font-semibold text-text-secondary">Sisa Waktu Pendaftaran:</p>
                        <p className="text-2xl font-bold text-primary">{timeLeft}</p>
                    </Card>
                )}

                {!successMessage ? (
                    <form onSubmit={handleSubmit}>
                        <Card className="mb-4">
                            <h2 className="text-xl font-bold mb-4">Data Atlet</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <Input label="Nama Lengkap Atlet" id="name" name="name" value={formData.name} onChange={handleFormChange} onBlur={handleNameBlur} required />
                                    {isCheckingName && <p className="text-xs text-text-secondary mt-1">Mencari data atlet...</p>}
                                    {existingSwimmer && (
                                        <div className="text-xs text-green-600 dark:text-green-400 mt-1 p-2 bg-green-500/10 rounded-md">
                                            Data ditemukan dan diisi otomatis. Bukan atlet yang benar?{' '}
                                            <button type="button" onClick={clearAutoFilledData} className="underline font-semibold">Klik di sini</button> untuk mengisi manual.
                                        </div>
                                    )}
                                </div>
                                <Input label="Nama Tim" id="club" name="club" value={formData.club} onChange={handleFormChange} required />
                                <Input label="Tahun Lahir" id="birthYear" name="birthYear" type="number" value={formData.birthYear} onChange={handleFormChange} required />
                                <Select label="Jenis Kelamin" id="gender" name="gender" value={formData.gender} onChange={handleFormChange}>
                                    <option value="Male">Laki-laki (Male)</option>
                                    <option value="Female">Perempuan (Female)</option>
                                </Select>
                                 <Select label="Kelompok Umur (KU) (Opsional)" id="ageGroup" name="ageGroup" value={formData.ageGroup} onChange={handleFormChange}>
                                    <option value="">-- Tanpa KU --</option>
                                    {ageOptions.map((ku: string) => <option key={ku} value={ku}>{ku}</option>)}
                                </Select>
                            </div>
                        </Card>

                        <Card>
                            <h2 className="text-xl font-bold mb-4">Pilih Nomor Lomba</h2>
                            {Object.entries(groupedAvailableEvents).length > 0 ? (
