const BrokenRecordsReport: React.FC<{ brokenRecords: BrokenRecord[] }> = ({ brokenRecords }) => {
    if (brokenRecords.length === 0) {
        return <p className="text-center text-text-secondary py-10">Tidak ada rekor yang terpecahkan dalam kompetisi ini.</p>;
    }

    return (
        <main className="space-y-6">
            {brokenRecords.map(({ record, newEventName, newHolder, newTime }, i) => (
                <section key={i} className="print-event-section bg-gray-50 p-4 rounded-lg border">
                    <h3 className="text-lg font-bold text-primary">{newEventName}</h3>
                    <div className="mt-2 grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="bg-green-100 p-3 rounded">
                            <h4 className="font-bold text-green-800">REKOR BARU</h4>
                            <p className="text-2xl font-semibold">{newHolder.name}</p>
                            <p className="text-md text-gray-700">{newHolder.club}</p>
                            <p className="text-3xl font-mono mt-2">{formatTime(newTime)}</p>
                        </div>
                        <div className="bg-red-100 p-3 rounded">
                            <h4 className="font-bold text-red-800">REKOR LAMA</h4>
                            <p className="text-lg font-semibold">{record.holderName}</p>
                            <p className="text-sm text-gray-600">{record.locationSet ? `${record.yearSet} - ${record.locationSet}` : record.yearSet}</p>
                            <p className="text-2xl font-mono mt-2 line-through">{formatTime(record.time)}</p>
                        </div>
                    </div>
                </section>
            ))}
        </main>
    );
};


export const PrintView: React.FC<PrintViewProps> = ({ events, swimmers, competitionInfo, isLoading }) => {
    const [activeReport, setActiveReport] = useState<'schedule' | 'program' | 'results' | 'medals' | 'medalsWithAthletes' | 'individualMedals' | 'individualMedalsByCategory' | 'brokenRecords'>('schedule');
    const [records, setRecords] = useState<SwimRecord[]>([]);
    const [brokenRecords, setBrokenRecords] = useState<BrokenRecord[]>([]);
    const [selectedSession, setSelectedSession] = useState<number>(0); // 0 means "All Sessions"
    const [selectedEventIds, setSelectedEventIds] = useState<string[]>([]);
    const [isDownloadingExcel, setIsDownloadingExcel] = useState(false);
    const { addNotification } = useNotification();

     useEffect(() => {
        if (!['program', 'results', 'individualMedalsByCategory'].includes(activeReport)) {
            setSelectedEventIds([]);
        }
    }, [activeReport]);

    useEffect(() => {
        const fetchRecords = async () => {
            const recordsData = await getRecords();
            setRecords(recordsData);
        };
        fetchRecords();
    }, []);

    useEffect(() => {
        const calculateBrokenRecords = () => {
            const broken: BrokenRecord[] = [];
            const swimmersMap = new Map<string, Swimmer>(swimmers.map(s => [s.id, s]));

            (events as SwimEvent[]).forEach((event: SwimEvent) => {
                if (!event.results) return;
                event.results.forEach((result: Result) => {
                    if (result.time > 0) {
                        const swimmer = swimmersMap.get(result.swimmerId);
                        if (!swimmer) return;

                        [RecordType.PORPROV, RecordType.NASIONAL].forEach(type => {
                            const record = records.find(r => 
                                r.type.toUpperCase() === type.toUpperCase() &&
                                r.gender === event.gender &&
                                r.distance === event.distance &&
                                r.style === event.style &&
                                (r.relayLegs ?? null) === (event.relayLegs ?? null) &&
                                (r.category ?? null) === (event.category ?? null)
                            );

                            if (record && result.time < record.time) {
                                broken.push({
                                    record,
                                    newEventName: formatEventName(event),
                                    newHolder: swimmer,
                                    newTime: result.time
                                });
                            }
                        });
                    }
                });
            });
            const uniqueBroken = [...new Map(broken.sort((a,b) => a.newTime - b.newTime).map(item => [item.record.id, item])).values()];
            setBrokenRecords(uniqueBroken);
        };

        if (events.length > 0 && records.length > 0) {
            calculateBrokenRecords();
        }
    }, [events, swimmers, records]);

    const handlePrint = () => {
        window.print();
    };

    const sessionOptions = useMemo(() => {
        const sessions = new Set<number>();
        (events as SwimEvent[]).forEach((e: SwimEvent) => {
            if (e.sessionNumber && e.sessionNumber > 0) {
                sessions.add(e.sessionNumber);
            }
        });
        return Array.from(sessions).sort((a, b) => a - b);
    }, [events]);

    const eventsWithGlobalNumbers = useMemo<ScheduledEvent[]>(() => {
        let globalCounter = 1;
        const allScheduled = [...(events as SwimEvent[])]
            .filter((e: SwimEvent) => e.sessionNumber && e.sessionNumber > 0)
            .sort((a: SwimEvent, b: SwimEvent) => {
                const sessionDiff = (a.sessionNumber ?? 0) - (b.sessionNumber ?? 0);
                if (sessionDiff !== 0) return sessionDiff;
                return (a.heatOrder ?? 0) - (b.heatOrder ?? 0);
            });

        return allScheduled.map((e: SwimEvent) => ({
            ...e,
            globalEventNumber: globalCounter++
        }));
    }, [events]);

    const eventsToDisplay = useMemo<ScheduledEvent[]>(() => {
        if (selectedEventIds.length > 0) {
            const selectedSet = new Set(selectedEventIds);
            return eventsWithGlobalNumbers.filter(e => selectedSet.has(e.id));
        }
        if (selectedSession === 0) {
            return eventsWithGlobalNumbers;
        }
        return eventsWithGlobalNumbers.filter(e => e.sessionNumber === selectedSession);
    }, [eventsWithGlobalNumbers, selectedSession, selectedEventIds]);


    if (isLoading) return <div className="flex justify-center mt-8"><Spinner /></div>;
    if (!competitionInfo) return <p className="text-center mt-8">Data kompetisi tidak tersedia.</p>;

    const getReportTitle = () => {
        if (selectedEventIds.length > 0) {
            const reportType = activeReport === 'program' ? 'Buku Acara' : 'Buku Hasil';
            if (selectedEventIds.length === 1) {
                const specificEvent = eventsWithGlobalNumbers.find(e => e.id === selectedEventIds[0]);
                return specificEvent ? `${reportType}: ${formatEventName(specificEvent)}` : reportType;
            }
            return `${reportType} (Pilihan Ganda)`;
        }

        const sessionSuffix = selectedSession > 0 && ['schedule', 'program', 'results'].includes(activeReport) ? ` - Sesi ${romanize(selectedSession)}` : '';
        switch (activeReport) {
            case 'schedule': return `Susunan Acara${sessionSuffix}`;
            case 'program': return `Buku Acara (Start List)${sessionSuffix}`;
            case 'results': return `Buku Hasil${sessionSuffix}`;
            case 'medals': return 'Rekap Medali Klub';
            case 'medalsWithAthletes': return 'Rekap Medali Klub & Atlet';
            case 'individualMedals': return 'Rekap Medali Atlet (Total)';
            case 'individualMedalsByCategory': return 'Klasemen Perorangan per Kategori (KU)';
            case 'brokenRecords': return 'Rekor Terpecahkan';
            default: return '';
        }
    };

    // --- EXCEL DOWNLOAD HANDLER ---
    const handleDownloadExcel = () => {
        if (typeof XLSX === 'undefined' || !competitionInfo) {
            addNotification('Pustaka Excel belum termuat or data kompetisi tidak ada.', 'error');
            return;
        }
        setIsDownloadingExcel(true);
        try {
            const wb = XLSX.utils.book_new();
            const reportTitle = getReportTitle();
            const swimmersMap = new Map<string, Swimmer>(swimmers.map(s => [s.id, s]));

            const createHeaderAoa = (title: string) => [
                [competitionInfo.eventName.split('\n')[0] || ''],
                [competitionInfo.eventName.split('\n')[1] || ''],
                [competitionInfo.eventName.split('\n')[2] || ''],
                [competitionInfo.eventDate ? new Date(competitionInfo.eventDate).toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }) : ''],
                [],
                [title],
                []
            ];

            switch(activeReport) {
                 case 'schedule': {
                    // FIX: Explicitly type `aoa` to allow mixed content types (string, number).
                    let aoa: (string | number | null | undefined)[][] = createHeaderAoa(reportTitle);
                    aoa.push(['No. Acara', 'Nomor Lomba', 'Sesi', 'Perkiraan Waktu Mulai']);
                    // FIX: Cast eventsToDisplay as any[] for the loop to resolve 'unknown' type errors.
                    (eventsToDisplay as any[]).forEach(e => {
                        const startTime = e.sessionDateTime ? new Date(e.sessionDateTime).toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' }) : 'TBD';
                        aoa.push([e.globalEventNumber, formatEventName(e), e.sessionNumber, startTime]);
                    });
                    const ws = XLSX.utils.aoa_to_sheet(aoa);
                    ws['!cols'] = [{wch: 10}, {wch: 60}, {wch: 10}, {wch: 20}];
                    XLSX.utils.book_append_sheet(wb, ws, 'Susunan Acara');
                    break;
                }

                case 'program':
                case 'results': {
                    // FIX: Explicitly type `aoa` to allow mixed content types (string, number).
                    let aoa: (string | number | null | undefined)[][] = createHeaderAoa(reportTitle);
                    const eventsBySession = eventsToDisplay.reduce((acc, event) => {
                        const sessionName = `Sesi ${romanize(event.sessionNumber || 0)}`;
                        if (!acc[sessionName]) acc[sessionName] = [];
                        acc[sessionName].push(event);
                        return acc;
                    }, {} as Record<string, ScheduledEvent[]>);

                    Object.entries(eventsBySession).forEach(([sessionName, sessionEvents]) => {
                        aoa.push([sessionName.toUpperCase()]);
                        aoa.push([]);

                        sessionEvents.forEach(event => {
                            aoa.push([`Nomor Acara ${event.globalEventNumber}: ${formatEventName(event)}`]);
                            const porprov = records.find(r => r.type === RecordType.PORPROV && r.gender === event.gender && r.distance === event.distance && r.style === event.style && (r.relayLegs ?? null) === (event.relayLegs ?? null) && (r.category ?? null) === (event.category ?? null));
                            const nasional = records.find(r => r.type === RecordType.NASIONAL && r.gender === event.gender && r.distance === event.distance && r.style === event.style && (r.relayLegs ?? null) === (event.relayLegs ?? null) && (r.category ?? null) === (event.category ?? null));
                            if (porprov) aoa.push([`Rekor PORPROV: ${formatTime(porprov.time)} - ${porprov.holderName} (${porprov.yearSet})`]);
                            if (nasional) aoa.push([`Rekor Nasional: ${formatTime(nasional.time)} - ${nasional.holderName} (${nasional.yearSet})`]);
                            aoa.push([]);

                            if (activeReport === 'program') {
                                const entries: Entry[] = (event.entries || []).map(entry => ({...entry, swimmer: swimmersMap.get(entry.swimmerId)!})).filter(e => e.swimmer);
                                const heats = generateHeats(entries, competitionInfo.numberOfLanes || 8);
                                if (heats.length === 0) { aoa.push(['(Belum ada peserta terdaftar)']); } 
                                else {
                                    // FIX: Cast heats as any[] for the loop to avoid 'unknown' errors inside the callback.
                                    (heats as any[]).forEach(heat => {
                                        aoa.push([`Seri ${heat.heatNumber} dari ${heats.length}`]);
                                        aoa.push(['Lintasan', 'Nama Atlet', 'KU', 'Tahun', 'Nama Tim', 'Waktu Unggulan']);
                                        Array.from({length: competitionInfo.numberOfLanes || 8}, (_,i)=>i+1).forEach(lane => {
                                            const assignment = (heat as any).assignments.find((a: any) => a.lane === lane);
                                            // FIX: Cast swimmer as Swimmer to prevent 'unknown' property access errors.
                                            const swimmer = assignment?.entry.swimmer as Swimmer | undefined;
                                            aoa.push([lane, swimmer?.name ?? '-', swimmer?.ageGroup ?? '-', swimmer?.birthYear ?? '-', swimmer?.club ?? '-', assignment ? formatTime(assignment.entry.seedTime) : '-']);
                                        });
                                        aoa.push([]);
                                    });
                                }
                            } else { // results
                                if (!event.results || event.results.length === 0) { aoa.push(['(Belum ada hasil tercatat)']); } 
                                else {
                                    const validResults = event.results.filter(r => r.time > 0).sort((a,b) => a.time - b.time);
                                    const sorted = [...event.results].sort((a,b) => (a.time > 0 && b.time > 0) ? a.time - b.time : (a.time < 0 ? 1 : -1)).map(r => ({...r, rank: r.time > 0 ? validResults.findIndex(vr => vr.swimmerId === r.swimmerId) + 1 : 0}));
                                    aoa.push(['Peringkat', 'Nama Atlet', 'KU', 'Tahun', 'Nama Tim', 'Waktu', 'Rekor']);
                                    sorted.forEach(res => {
                                        // FIX: Cast swimmersMap.get() result as Swimmer to resolve 'unknown' error.
                                        const swimmer = swimmersMap.get(res.swimmerId) as Swimmer | undefined;
                                        const recordsBrokenText = brokenRecords.filter(br => br.newHolder.id === swimmer?.id && br.newTime === res.time && br.record.style === event.style && br.record.distance === event.distance).map(br => br.record.type).join(', ');
                                        aoa.push([res.rank > 0 ? res.rank : formatTime(res.time), swimmer?.name || 'N/A', event.relayLegs ? '-' : (swimmer?.ageGroup || '-'), event.relayLegs ? '-' : (swimmer?.birthYear || ''), swimmer?.club || 'N/A', formatTime(res.time), recordsBrokenText]);
                                    });
                                }
                            }
                            aoa.push([]);
                        });
                    });
                    const ws = XLSX.utils.aoa_to_sheet(aoa);
                    ws['!cols'] = [{wch:10},{wch:30},{wch:10},{wch:10},{wch:30},{wch:15},{wch:10}];
                    XLSX.utils.book_append_sheet(wb, ws, reportTitle);
                    break;
                }

                case 'medals': {
                     const allClubs = [...new Set(swimmers.map(s => s.club))];
                     // FIX: Explicitly type the accumulator in the reduce function to prevent TypeScript from inferring it as `{}`, resolving several type errors.
                     const clubMedals = allClubs.reduce((acc: Record<string, { gold: number, silver: number, bronze: number }>, club: string) => ({ ...acc, [club]: { gold: 0, silver: 0, bronze: 0 } }), {} as Record<string, { gold: number, silver: number, bronze: number }>);
                     // FIX: Cast events as SwimEvent[] to ensure correct type inference for results and swimmerId lookup.
                     (events as SwimEvent[]).forEach((event: SwimEvent) => { if (!event.results) return; [...(event.results as Result[])].filter((r: Result) => r.time > 0).sort((a: Result, b: Result) => a.time - b.time).slice(0, 3).forEach((result: Result, i: number) => { const rank = i + 1; const swimmer: Swimmer | undefined = swimmersMap.get(result.swimmerId) as Swimmer | undefined; if (swimmer && clubMedals[swimmer.club]) { if (rank === 1) clubMedals[swimmer.club].gold++; else if (rank === 2) clubMedals[swimmer.club].silver++; else if (rank === 3) clubMedals[swimmer.club].bronze++; } }); });
                     const sortedData = Object.entries(clubMedals).sort(([, a], [, b]) => b.gold - a.gold || b.silver - a.silver || b.bronze - a.bronze);

                    // FIX: Explicitly type `aoa` to allow mixed content types (string, number).
                     const aoa: (string | number | null | undefined)[][] = createHeaderAoa(reportTitle);
                     aoa.push(['#', 'Nama Tim', '🥇', '🥈', '🥉', 'Total']);
                     sortedData.forEach(([club, medals], i) => {
                        aoa.push([i+1, club, medals.gold, medals.silver, medals.bronze, medals.gold + medals.silver + medals.bronze]);
                     });
                     const ws = XLSX.utils.aoa_to_sheet(aoa);
                     ws['!cols'] = [{wch:5},{wch:40},{wch:5},{wch:5},{wch:5},{wch:10}];
                     XLSX.utils.book_append_sheet(wb, ws, reportTitle);
                     break;
                }
                case 'medalsWithAthletes': {
                     type MedalCounts = { gold: number, silver: number, bronze: number }; type Win = { eventName: string, rank: number, time: number }; type AthleteWins = { swimmer: Swimmer, wins: Win[] }; type ClubData = { medals: MedalCounts, athletes: Record<string, AthleteWins> };
                    const clubDataRecalc: Record<string, ClubData> = {}; (swimmers as Swimmer[]).forEach((s: Swimmer) => { if (!clubDataRecalc[s.club]) { clubDataRecalc[s.club] = { medals: { gold: 0, silver: 0, bronze: 0 }, athletes: {} }; }});
                    // FIX: Cast swimmer lookup as Swimmer to prevent 'unknown' errors.
                    (events as SwimEvent[]).forEach((event: SwimEvent) => { if (!event.results) return; [...(event.results as Result[])].filter((r: Result) => r.time > 0).sort((a: Result, b: Result) => a.time - b.time).slice(0, 3).forEach((result: Result, i: number) => { const rank = i + 1; const swimmer: Swimmer | undefined = swimmersMap.get(result.swimmerId) as Swimmer | undefined; if (swimmer) { const club = clubDataRecalc[swimmer.club]; if (rank === 1) club.medals.gold++; else if (rank === 2) club.medals.silver++; else if (rank === 3) club.medals.bronze++; if (!club.athletes[swimmer.id]) { club.athletes[swimmer.id] = { swimmer, wins: [] }; } club.athletes[swimmer.id].wins.push({ eventName: formatEventName(event), rank, time: result.time }); } }); });
                    const sortedData = Object.entries(clubDataRecalc).sort(([cA, a], [cB, b]) => b.medals.gold - a.medals.gold || b.medals.silver - a.medals.silver || b.medals.bronze - a.medals.bronze || cA.localeCompare(cB));

                    // FIX: Explicitly type `aoa` to allow mixed content types (string, number).
                    let aoa: (string | number | null | undefined)[][] = createHeaderAoa(reportTitle);
                    sortedData.forEach(([clubName, clubData]) => {
                         const athletesWithWins = Object.values(clubData.athletes).filter((a: AthleteWins) => a.wins.length > 0);
                         if (athletesWithWins.length === 0) return;
                         aoa.push([]);
                         aoa.push([clubName, `🥇${clubData.medals.gold}`, `🥈${clubData.medals.silver}`, `🥉${clubData.medals.bronze}`]);
                         aoa.push(['Nama Atlet', 'Nomor Lomba yang Dimenangkan']);
                         athletesWithWins.forEach(({ swimmer, wins }: { swimmer: Swimmer; wins: Win[] }) => {
                            aoa.push([swimmer.name]);
                            wins.sort((a,b)=>a.rank-b.rank).forEach(win => {
                                aoa.push(['', `${win.rank === 1 ? '🥇' : win.rank === 2 ? '🥈' : '🥉'} ${win.eventName} - ${formatTime(win.time)}`]);
                            });
                         });
                    });
                    const ws = XLSX.utils.aoa_to_sheet(aoa);
                    ws['!cols'] = [{wch:30},{wch:60}];
                    XLSX.utils.book_append_sheet(wb, ws, reportTitle);
                    break;
                }
                case 'individualMedals': {
                    const individualMedals: Record<string, { swimmer: Swimmer, gold: number, silver: number, bronze: number }> = {};
                    // FIX: Cast swimmer lookup as Swimmer to prevent 'unknown' errors.
                    (events as SwimEvent[]).forEach((event: SwimEvent) => { if (event.results && event.results.length > 0 && event.gender !== Gender.MIXED) { [...(event.results as Result[])].filter((r: Result) => r.time > 0).sort((a: Result, b: Result) => a.time - b.time).slice(0, 3).forEach((result: Result, i: number) => { const rank = i + 1; const swimmer: Swimmer | undefined = swimmersMap.get(result.swimmerId) as Swimmer | undefined; if (swimmer) { if (!individualMedals[swimmer.id]) { individualMedals[swimmer.id] = { swimmer, gold: 0, silver: 0, bronze: 0 }; } if (rank === 1) individualMedals[swimmer.id].gold++; else if (rank === 2) individualMedals[swimmer.id].silver++; else if (rank === 3) individualMedals[swimmer.id].bronze++; } }); } });
                    const sortedStandings = Object.values(individualMedals).sort((a, b) => b.gold - a.gold || b.silver - a.silver || b.bronze - a.bronze || a.swimmer.name.localeCompare(b.swimmer.name));
                    const maleStandings = sortedStandings.filter(s => s.swimmer.gender === 'Male');
                    const femaleStandings = sortedStandings.filter(s => s.swimmer.gender === 'Female');

                    const maleData = maleStandings.map((s, i: number) => ({'#':i+1, 'Nama':s.swimmer.name, 'Klub':s.swimmer.club, '🥇':s.gold, '🥈':s.silver, '🥉':s.bronze}));
                    const femaleData = femaleStandings.map((s, i: number) => ({'#':i+1, 'Nama':s.swimmer.name, 'Klub':s.swimmer.club, '🥇':s.gold, '🥈':s.silver, '🥉':s.bronze}));

                    const ws_male = XLSX.utils.json_to_sheet(maleData); ws_male['!cols'] = [{wch:5},{wch:30},{wch:30},{wch:5},{wch:5},{wch:5}];
                    const ws_female = XLSX.utils.json_to_sheet(femaleData); ws_female['!cols'] = [{wch:5},{wch:30},{wch:30},{wch:5},{wch:5},{wch:5}];

                    XLSX.utils.book_append_sheet(wb, ws_male, 'Putra');
                    XLSX.utils.book_append_sheet(wb, ws_female, 'Putri');
                    break;
                }
                case 'individualMedalsByCategory': {
                    type Standing = { swimmer: Swimmer, gold: number, silver: number, bronze: number };
                    const medalsByAgeGroup: Record<string, Record<string, Standing>> = {};
                    // FIX: Cast swimmer lookup as Swimmer to prevent 'unknown' errors.
                    (events as SwimEvent[]).forEach((event: SwimEvent) => { if (event.results && event.results.length > 0 && event.gender !== Gender.MIXED) { [...(event.results as Result[])].filter((r: Result) => r.time > 0).sort((a: Result, b: Result) => a.time - b.time).slice(0, 3).forEach((result: Result, i: number) => { const rank = i + 1; const swimmer: Swimmer | undefined = swimmersMap.get(result.swimmerId) as Swimmer | undefined; if (swimmer) { const ageGroup = swimmer.ageGroup || 'Umum'; if (!medalsByAgeGroup[ageGroup]) medalsByAgeGroup[ageGroup] = {}; if (!medalsByAgeGroup[ageGroup][swimmer.id]) { medalsByAgeGroup[ageGroup][swimmer.id] = { swimmer, gold: 0, silver: 0, bronze: 0 }; } if (rank === 1) medalsByAgeGroup[ageGroup][swimmer.id].gold++; else if (rank === 2) medalsByAgeGroup[ageGroup][swimmer.id].silver++; else if (rank === 3) medalsByAgeGroup[ageGroup][swimmer.id].bronze++; } }); } });
                    const finalData = Object.entries(medalsByAgeGroup).map(([ageGroup, swimmersMedals]) => {
                        const sorted = Object.values(swimmersMedals).sort((a, b) => b.gold - a.gold || b.silver - a.silver || b.bronze - a.bronze || a.swimmer.name.localeCompare(b.swimmer.name));
                        return { ageGroup, maleStandings: sorted.filter(s => s.swimmer.gender === 'Male'), femaleStandings: sorted.filter(s => s.swimmer.gender === 'Female') };
                    }).sort((a, b) => a.ageGroup.localeCompare(b.ageGroup));

                    finalData.forEach((cat: { ageGroup: string; maleStandings: Standing[]; femaleStandings: Standing[] }) => {
                       const maleData = cat.maleStandings.map((s: Standing, i: number) => ({'#':i+1, 'Nama':s.swimmer.name, 'Klub':s.swimmer.club, '🥇':s.gold, '🥈':s.silver, '🥉':s.bronze}));
                       const femaleData = cat.femaleStandings.map((s: Standing, i: number) => ({'#':i+1, 'Nama':s.swimmer.name, 'Klub':s.swimmer.club, '🥇':s.gold, '🥈':s.silver, '🥉':s.bronze}));
                       const aoa = [
                           ['Klasemen Putra'],
                           ['#', 'Nama Atlet', 'Nama Tim', '🥇', '🥈', '🥉'],
                           ...maleData.map(d => [d['#'], d.Nama, d.Klub, d['🥇'], d['🥈'], d['🥉']]),
                           [],
                           ['Klasemen Putri'],
                           ['#', 'Nama Atlet', 'Nama Tim', '🥇', '🥈', '🥉'],
                           ...femaleData.map(d => [d['#'], d.Nama, d.Klub, d['🥇'], d['🥈'], d['🥉']])
                       ];
                       const ws_cat = XLSX.utils.aoa_to_sheet(aoa);
                       ws_cat['!cols'] = [{wch:5},{wch:30},{wch:30},{wch:5},{wch:5},{wch:5}];
                       XLSX.utils.book_append_sheet(wb, ws_cat, cat.ageGroup.replace(/[/\\?%*:|"[\]]/g, '-'));
                    });
                    break;
                }
                case 'brokenRecords': {
                    if (brokenRecords.length > 0) {
                        const data = brokenRecords.map((br: BrokenRecord) => ({ 'Nomor Lomba': br.newEventName, 'Rekor Baru': formatTime(br.newTime), 'Pemegang Rekor Baru': br.newHolder.name, 'Klub': br.newHolder.club, 'Rekor Lama': formatTime(br.record.time), 'Pemegang Rekor Lama': br.record.holderName, 'Tipe Rekor': br.record.type }));
                        const ws = XLSX.utils.json_to_sheet(data);
                        ws['!cols'] = [{wch:40},{wch:15},{wch:30},{wch:30},{wch:15},{wch:30},{wch:15}];
                        XLSX.utils.book_append_sheet(wb, ws, reportTitle);
                    }
                    break;
                }
            }

            if (wb.SheetNames.length > 0) {
                XLSX.writeFile(wb, `${reportTitle.replace(/[\/\\?%*:|"<>]/g, '-')}.xlsx`);
            } else {
                 addNotification('Tidak ada data untuk diunduh untuk laporan ini.', 'info');
            }
        } catch (error: any) {
            console.error("Gagal membuat file Excel:", error);
            addNotification(`Gagal membuat file Excel: ${error.message || 'Unknown error'}`, 'error');
        } finally {
            setIsDownloadingExcel(false);
        }
    };

    return (
        <div className="flex flex-col h-full">
            <div className="no-print space-y-4 mb-6">
                <h1 className="text-3xl font-bold">Cetak & Unduh Laporan</h1>
                <div className="bg-surface p-4 rounded-lg border border-border flex flex-col gap-4">
                    <div className="flex flex-wrap items-center justify-between gap-4">
                        <div className="flex flex-wrap gap-2">
                            <Button variant={activeReport === 'schedule' ? 'primary' : 'secondary'} onClick={() => setActiveReport('schedule')}>Susunan Acara</Button>
                            <Button variant={activeReport === 'program' ? 'primary' : 'secondary'} onClick={() => setActiveReport('program')}>Buku Acara</Button>
                            <Button variant={activeReport === 'results' ? 'primary' : 'secondary'} onClick={() => setActiveReport('results')}>Buku Hasil</Button>
                            <Button variant={activeReport === 'medals' ? 'primary' : 'secondary'} onClick={() => setActiveReport('medals')}>Rekap Medali Klub</Button>
                            <Button variant={activeReport === 'medalsWithAthletes' ? 'primary' : 'secondary'} onClick={() => setActiveReport('medalsWithAthletes')}>Rekap Medali Klub & Atlet</Button>
                            <Button variant={activeReport === 'individualMedals' ? 'primary' : 'secondary'} onClick={() => setActiveReport('individualMedals')}>Rekap Medali Atlet (Total)</Button>
                            <Button variant={activeReport === 'individualMedalsByCategory' ? 'primary' : 'secondary'} onClick={() => setActiveReport('individualMedalsByCategory')}>Klasemen Perorangan (Kategori)</Button>
                            <Button variant={activeReport === 'brokenRecords' ? 'primary' : 'secondary'} onClick={() => setActiveReport('brokenRecords')}>Rekor Terpecahkan</Button>
                        </div>
                        <div className="flex space-x-2">
                             <Button onClick={handleDownloadExcel} variant="secondary" className="flex items-center space-x-2" disabled={isDownloadingExcel}>
                                {isDownloadingExcel ? <Spinner/> : <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>}
                                <span>Unduh Excel</span>
                            </Button>
                            <Button onClick={handlePrint} className="flex items-center space-x-2">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm7-14a2 2 0 10-4 0v4a2 2 0 104 0V3z" /></svg>
                                <span>Cetak / PDF</span>
                            </Button>
                        </div>
                    </div>
                    <div className="flex flex-wrap items-end gap-4 pt-4 border-t border-border">
                        {['schedule', 'program', 'results'].includes(activeReport) && (
                            <div>
                                <label htmlFor="session-filter" className="text-sm font-medium text-text-secondary">Filter Sesi</label>
                                <select 
                                    id="session-filter"
                                    value={selectedSession} 
                                    onChange={(e) => setSelectedSession(Number(e.target.value))}
                                    className="w-full mt-1 bg-background border border-border rounded-md px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary disabled:opacity-50 disabled:cursor-not-allowed"
                                    disabled={selectedEventIds.length > 0}
                                    title={selectedEventIds.length > 0 ? 'Filter sesi dinonaktifkan saat nomor lomba spesifik dipilih' : 'Pilih sesi untuk dicetak'}
                                >
                                    <option value={0}>Semua Sesi</option>
                                    {sessionOptions.map(s => (
                                        <option key={s} value={s}>Sesi {romanize(s)}</option>
                                    ))}
                                </select>
                            </div>
                        )}
                         {['program', 'results'].includes(activeReport) && (
                            <div className="flex-grow max-w-md">
                                <div className="flex justify-between items-center mb-1">
                                    <label htmlFor="event-filter-container" className="text-sm font-medium text-text-secondary">Pilih Nomor Lomba untuk Dicetak</label>
                                    {selectedEventIds.length > 0 && (
                                        <button onClick={() => setSelectedEventIds([])} className="text-xs text-blue-500 hover:underline">Reset Pilihan</button>
                                    )}
                                </div>
                                <div id="event-filter-container" className="w-full bg-background border border-border rounded-md p-2 text-sm h-40 overflow-y-auto space-y-1">
                                    {eventsWithGlobalNumbers.map(event => (
                                        <div key={event.id} className="flex items-center p-1 rounded hover:bg-surface">
                                            <input
                                                type="checkbox"
                                                id={`event-checkbox-${event.id}`}
                                                value={event.id}
                                                checked={selectedEventIds.includes(event.id)}
                                                onChange={(e) => {
                                                    const eventId = e.target.value;
                                                    setSelectedEventIds(prev => 
                                                        prev.includes(eventId) 
                                                            ? prev.filter(id => id !== eventId) 
                                                            : [...prev, eventId]
                                                    );
                                                }}
                                                className="h-4 w-4 rounded border-gray-300 text-primary focus:ring-primary"
                                            />
                                            <label htmlFor={`event-checkbox-${event.id}`} className="ml-2 text-text-primary select-none cursor-pointer flex-grow">
                                                {`No. ${event.globalEventNumber}: ${formatEventName(event)}`}
                                            </label>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <div className="flex-grow bg-gray-100 dark:bg-gray-900 overflow-auto p-4 md:p-8 print:p-0 print:bg-white print:overflow-visible">
                <div className="print-preview-content">
                    <ReportHeader info={competitionInfo} title={getReportTitle()} />

                    {activeReport === 'schedule' && <ScheduleOfEvents events={eventsToDisplay} />}
                    {activeReport === 'program' && <ProgramBook events={eventsToDisplay} swimmers={swimmers} info={competitionInfo} records={records} />}
                    {activeReport === 'results' && <EventResults events={eventsToDisplay} swimmers={swimmers} info={competitionInfo} records={records} brokenRecords={brokenRecords} />}
                    {activeReport === 'medals' && <ClubMedalStandings events={events} swimmers={swimmers} info={competitionInfo} />}
                    {activeReport === 'medalsWithAthletes' && <ClubMedalStandingsWithAthletes events={events} swimmers={swimmers} />}
                    {activeReport === 'individualMedals' && <IndividualMedalStandings events={events} swimmers={swimmers} />}
                    {activeReport === 'individualMedalsByCategory' && <IndividualMedalStandingsByCategory events={events} swimmers={swimmers} />}
                    {activeReport === 'brokenRecords' && <BrokenRecordsReport brokenRecords={brokenRecords} />}


                    <ReportFooter info={competitionInfo} />
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import type { CompetitionInfo, SwimEvent, Swimmer, FormattableEvent } from '../types';
import { getEventsForRegistration, processOnlineRegistration, findSwimmerByName } from '../services/databaseService';
import { Card } from './ui/Card';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { Select } from './ui/Select';
import { Spinner } from './ui/Spinner';
import { formatEventName, toTitleCase, formatTime, translateSwimStyle, AGE_GROUP_OPTIONS } from '../constants';
import { SwimStyle, Gender } from '../types';

interface OnlineRegistrationViewProps {
    competitionInfo: CompetitionInfo | null;
    onBackToLogin: () => void;
    onRegistrationSuccess: () => void;
}

type RegistrationTime = { min: string; sec: string; ms: string };
type SelectedEvents = Record<string, { selected: boolean; time: RegistrationTime }>;

interface OnlineRegistrationResponse {
    success: boolean;
    message: string;
    swimmer: Swimmer | null;
    previouslyRegisteredEvents?: FormattableEvent[];
}

const parseTimeToMs = (time: RegistrationTime): number => {
    const minutes = parseInt(time.min, 10) || 0;
    const seconds = parseInt(time.sec, 10) || 0;
    const hundredths = parseInt(time.ms, 10) || 0;
    if (minutes === 99 && seconds === 99 && hundredths === 99) {
        return 0; // Treat as No Time
    }
    return (minutes * 60 * 1000) + (seconds * 1000) + (hundredths * 10);
};

const ChevronDownIcon = ({ isOpen }: { isOpen: boolean }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={`h-6 w-6 transform transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
    </svg>
);


export const OnlineRegistrationView: React.FC<OnlineRegistrationViewProps> = ({
    competitionInfo,
    onBackToLogin,
    onRegistrationSuccess,
}) => {
    const [localEvents, setLocalEvents] = useState<SwimEvent[]>([]);
    const [isDataLoading, setIsDataLoading] = useState(true);
    const [formData, setFormData] = useState({
        name: '',
        birthYear: new Date().getFullYear() - 10,
        gender: 'Male' as 'Male' | 'Female',
        club: '',
        ageGroup: '',
    });
    const [selectedEvents, setSelectedEvents] = useState<SelectedEvents>({});
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState('');
    const [successMessage, setSuccessMessage] = useState('');

    // State for auto-fill feature
    const [isCheckingName, setIsCheckingName] = useState(false);
    const [existingSwimmer, setExistingSwimmer] = useState<Swimmer | null>(null);

    // State for deadline countdown
    const [timeLeft, setTimeLeft] = useState('');
    const [isDeadlinePassed, setIsDeadlinePassed] = useState(false);

    // State for accordion
    const [openAccordion, setOpenAccordion] = useState<SwimStyle | null>(null);

    // Dynamic Age Groups Logic
    const ageOptions = useMemo(() => {
        if (competitionInfo?.ageGroups) {
            return competitionInfo.ageGroups.split('\n').map(s => s.trim()).filter(Boolean);
        }
        return AGE_GROUP_OPTIONS;
    }, [competitionInfo]);

    useEffect(() => {
        const fetchEvents = async () => {
            setIsDataLoading(true);
            const onlineEvents = await getEventsForRegistration();
            setLocalEvents(onlineEvents);
            setIsDataLoading(false);
        };

        fetchEvents();
    }, []);

    useEffect(() => {
        if (!competitionInfo?.registrationDeadline) {
            setIsDeadlinePassed(false);
            setTimeLeft('');
            return;
        }

        const deadline = new Date(competitionInfo.registrationDeadline);

        const updateCountdown = () => {
            const now = new Date();
            const difference = deadline.getTime() - now.getTime();

            if (difference <= 0) {
                setIsDeadlinePassed(true);
                setTimeLeft('Batas waktu pendaftaran telah berakhir.');
                if (intervalId) clearInterval(intervalId);
                return;
            }

            const days = Math.floor(difference / (1000 * 60 * 60 * 24));
            const hours = Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
            const minutes = Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60));
            const seconds = Math.floor((difference % (1000 * 60)) / 1000);

            setTimeLeft(`${days} hari ${hours} jam ${minutes} menit ${seconds} detik`);
        };

        updateCountdown();
        const intervalId = setInterval(updateCountdown, 1000);

        return () => clearInterval(intervalId);
    }, [competitionInfo?.registrationDeadline]);

    const handleAccordionToggle = (style: SwimStyle) => {
        setOpenAccordion(prev => (prev === style ? null : style));
    };

    const isFormValid = useMemo(() => {
        const hasPersonalInfo = formData.name.trim() !== '' && formData.club.trim() !== '' && formData.ageGroup !== '';
        // FIX: Explicitly cast value from Object.values to resolve 'unknown' type error.
        const hasSelectedEvent = Object.values(selectedEvents).some((e: any) => (e as { selected: boolean }).selected);
        return hasPersonalInfo && hasSelectedEvent;
    }, [formData, selectedEvents]);

    const availableEvents = useMemo(() => {
        const registeredEventIds = new Set<string>();
        if (existingSwimmer) {
            localEvents.forEach(event => {
                if (event.entries.some(entry => entry.swimmerId === existingSwimmer.id)) {
                    registeredEventIds.add(event.id);
                }
            });
        }

        return localEvents
            .filter((event: SwimEvent) => {
                if (registeredEventIds.has(event.id)) return false;

                // 1. Filter by Gender
                const genderMatch = event.gender === "Mixed" || 
                                   (formData.gender === "Male" && event.gender === "Men's") || 
                                   (formData.gender === "Female" && event.gender === "Women's");

                if (!genderMatch) return false;

                // 2. Filter by Category (KU)
                // If user has selected an age group, show only events matching that group OR "Open" events (category null)
                if (formData.ageGroup) {
                    return !event.category || event.category === formData.ageGroup;
                }

                // If ageGroup is not selected, we don't show specific events to avoid wrong selections
                return false;
            })
            .sort((a,b) => a.distance - b.distance || a.style.localeCompare(b.style));
    }, [localEvents, formData.gender, formData.ageGroup, existingSwimmer]);

    const groupedAvailableEvents = useMemo(() => {
        return availableEvents.reduce((acc: Record<SwimStyle, SwimEvent[]>, event: SwimEvent) => {
            const style = event.style;
            if (!acc[style]) {
                acc[style] = [];
            }
            acc[style].push(event);
            return acc;
        }, {} as Record<SwimStyle, SwimEvent[]>);
    }, [availableEvents]);

    const selectedEventCount = useMemo(() => {
        // FIX: Explicitly cast value from Object.values to resolve 'unknown' type error.
        return Object.values(selectedEvents).filter((e: any) => (e as { selected: boolean }).selected).length;
    }, [selectedEvents]);

    // Calculate a summary of selected events for the review card
    const selectedEventsSummary = useMemo(() => {
        // FIX: Explicitly cast Object.entries results to resolve 'unknown' property access errors.
        return (Object.entries(selectedEvents) as [string, any][])
            .filter(([_, val]) => (val as { selected: boolean }).selected)
            .map(([eventId, val]) => {
                const event = localEvents.find(e => e.id === eventId);
                if (!event) return null;

                const typedVal = val as { time: RegistrationTime };
                // Format display time
                let timeStr = 'NT';
                const min = typedVal.time.min || '0';
                const sec = typedVal.time.sec || '0';
                const ms = typedVal.time.ms || '0';

                if (min === '99' && sec === '99' && ms === '99') {
                    timeStr = 'NT';
                } else {
                    timeStr = `${min.padStart(2, '0')}:${sec.padStart(2, '0')}.${ms.padStart(2, '0')}`;
                }

                return { event, timeStr };
            })
            .filter((item): item is { event: SwimEvent, timeStr: string } => item !== null)
            .sort((a, b) => {
                // Sort summary by style then distance
                const styleCompare = a.event.style.localeCompare(b.event.style);
                if (styleCompare !== 0) return styleCompare;
                return a.event.distance - b.event.distance;
            });
    }, [selectedEvents, localEvents]);


    const handleFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        let finalValue: string | number = value;

        if (name === 'birthYear') {
            finalValue = parseInt(value);
        } else if (name === 'name' || name === 'club') {
            finalValue = toTitleCase(value);
        }

        setFormData(prev => ({ ...prev, [name]: finalValue }));
        setError('');
        setSuccessMessage('');
    };

    const handleEventSelectionChange = (eventId: string) => {
        setSelectedEvents(prev => ({
            ...prev,
            [eventId]: {
                selected: !prev[eventId]?.selected,
                time: prev[eventId]?.time || { min: '99', sec: '99', ms: '99' },
            },
        }));
    };

    const handleTimeChange = (eventId: string, part: keyof RegistrationTime, value: string) => {
        setSelectedEvents(prev => {
            const currentEvent = prev[eventId] || { selected: true, time: { min: '99', sec: '99', ms: '99' } };
            return {
                ...prev,
                [eventId]: {
                    ...currentEvent,
                    time: { ...currentEvent.time, [part]: value },
                },
            };
        });
    };

    const handleSetNoTime = (eventId: string) => {
        handleTimeChange(eventId, 'min', '99');
        handleTimeChange(eventId, 'sec', '99');
        handleTimeChange(eventId, 'ms', '99');
    };

    const handleNameBlur = async (e: React.FocusEvent<HTMLInputElement>) => {
        const swimmerName = e.target.value.trim();
        if (swimmerName.length < 3) {
            if (existingSwimmer) {
                setExistingSwimmer(null);
                setFormData(prev => ({ ...prev, club: '', birthYear: new Date().getFullYear() - 10, gender: 'Male', ageGroup: '' }));
            }
            return;
        }
        setIsCheckingName(true);
        const foundSwimmer = await findSwimmerByName(swimmerName);
        setIsCheckingName(false);
        if (foundSwimmer) {
            setFormData({
                name: foundSwimmer.name,
                club: foundSwimmer.club,
                birthYear: foundSwimmer.birthYear,
                gender: foundSwimmer.gender,
                ageGroup: foundSwimmer.ageGroup || '',
            });
            setExistingSwimmer(foundSwimmer);
        } else if (existingSwimmer) {
            clearAutoFilledData();
        }
    };

    const clearAutoFilledData = () => {
        setExistingSwimmer(null);
        setFormData(prev => ({ ...prev, club: '', birthYear: new Date().getFullYear() - 10, gender: 'Male', ageGroup: '' }));
        setTimeout(() => document.getElementById('club')?.focus(), 0);
    };


    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setSuccessMessage('');
        setIsSubmitting(true);

        if (!formData.name.trim() || !formData.club.trim() || !formData.ageGroup) {
            setError('Data atlet (Nama, Tim, dan KU) wajib diisi lengkap.');
            setIsSubmitting(false);
            return;
        }

        const registrationsToSubmit = [];
        for (const [eventId, val] of Object.entries(selectedEvents)) {
            const eventValue = val as { selected: boolean; time: RegistrationTime };
            if (eventValue.selected) {
                const min = parseInt(eventValue.time.min, 10) || 0;
                const sec = parseInt(eventValue.time.sec, 10) || 0;
                const ms = parseInt(eventValue.time.ms, 10) || 0;

                if (sec >= 60 && !(min === 99 && sec === 99 && ms === 99)) {
                    const eventDetails = availableEvents.find(e => e.id === eventId);
                    const eventName = eventDetails ? formatEventName(eventDetails) : `nomor lomba ID ${eventId}`;
                    setError(`Error pada ${eventName}: Input detik harus di bawah 60.`);
                    setIsSubmitting(false);
                    return;
                }

                registrationsToSubmit.push({
                    eventId,
                    seedTime: parseTimeToMs(eventValue.time),
                });
            }
        }

        if (registrationsToSubmit.length === 0) {
            setError('Anda harus memilih setidaknya satu nomor lomba.');
            setIsSubmitting(false);
            return;
        }

        const result: OnlineRegistrationResponse = await processOnlineRegistration(formData, registrationsToSubmit);
        setIsSubmitting(false);

        if (result.success && result.swimmer) {
            const swimmerName = result.swimmer.name;

            // Newly registered events formatted with their seed time
            const newlyRegisteredEventsList = registrationsToSubmit.map(reg => {
                const event = localEvents.find(e => e.id === reg.eventId);
                const eventName = event ? formatEventName(event) : 'Nomor Lomba Tidak Dikenal';
                const time = formatTime(reg.seedTime);
                return `• ${eventName} (Waktu: ${time})`;
            });

            // Previously registered events (without seed time, as we don't have it easily)
            // FIX: Explicitly cast result.previouslyRegisteredEvents as any[] to resolve 'unknown' type errors.
            const eventsFromServer = ((result.previouslyRegisteredEvents || []) as any[]);
            const previouslyRegisteredEventsList = eventsFromServer.map((event: any) => {
                const formattableEvent: FormattableEvent = {
                    distance: event.distance,
                    style: event.style,
                    gender: event.gender,
                    relayLegs: event.relay_legs, // Use snake_case from server
                    category: event.category,
                };
                return `• ${formatEventName(formattableEvent)}`;
            });

            // Combine all event strings and sort them for a clean list
            const allRegisteredEventsString = [
                ...newlyRegisteredEventsList,
                ...previouslyRegisteredEventsList,
            ].sort().join('\n');

            const successText = (
                <div className="text-left">
                    <p className="font-bold text-lg mb-2">Pendaftaran untuk {swimmerName} berhasil!</p>
                    <p className="mb-2">Anda sekarang terdaftar di nomor lomba berikut:</p>
                    <pre className="bg-background p-2 rounded-md text-sm whitespace-pre-wrap max-h-60 overflow-y-auto">
                        {allRegisteredEventsString}
                    </pre>
                </div>
            );

            setSuccessMessage(successText as any); // Cast to any to allow ReactNode
            onRegistrationSuccess();

            // Reset form for next entry
            setFormData({
                name: '',
                birthYear: new Date().getFullYear() - 10,
                gender: 'Male',
                club: '',
                ageGroup: '',
            });
            setSelectedEvents({});
            setExistingSwimmer(null);

        } else {
            setError(result.message || 'Terjadi kesalahan yang tidak diketahui.');
        }
    };

    const isRegistrationDisabled = isDeadlinePassed || !competitionInfo?.isRegistrationOpen;

    if (isDataLoading) {
        return (
            <div className="min-h-screen bg-background flex flex-col items-center justify-center p-4">
                <Spinner />
                <p className="text-text-secondary mt-4">Memuat data kompetisi...</p>
            </div>
        );
    }

     if (isRegistrationDisabled && !isDataLoading) {
        return (
             <div className="min-h-screen bg-gradient-to-br from-gray-100 to-slate-200 dark:from-slate-800 dark:to-gray-900 flex flex-col items-center justify-center p-4 text-center">
                <Card className="max-w-xl">
                    <h1 className="text-2xl font-bold text-primary mb-4">{competitionInfo?.eventName.split('\n')[0]}</h1>
                    <p className="text-lg text-red-500 font-semibold mb-2">Pendaftaran Online Saat Ini Ditutup</p>
                    <p className="text-text-secondary mb-6">
                        {timeLeft || 'Pendaftaran untuk kompetisi ini belum dibuka atau sudah berakhir. Silakan hubungi panitia untuk informasi lebih lanjut.'}
                    </p>
                    <Button onClick={onBackToLogin}>Kembali ke Halaman Utama</Button>
                </Card>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gradient-to-br from-sky-100 to-blue-200 dark:from-slate-800 dark:to-sky-900 flex flex-col items-center p-4">
            <div className="w-full max-w-4xl mx-auto">
                 <header className="text-center py-6">
                    {competitionInfo?.eventLogo && <img src={competitionInfo.eventLogo} alt="Logo Acara" className="mx-auto h-20 md:h-24 object-contain mb-4" />}
                    {competitionInfo && (
                        <div>
                            <h1 className="text-3xl md:text-5xl font-extrabold text-primary tracking-tight">{competitionInfo.eventName.split('\n')[0]}</h1>
                            <h2 className="text-xl md:text-2xl font-semibold text-text-secondary tracking-wide mt-1">{competitionInfo.eventName.split('\n')[1]}</h2>
                        </div>
                    )}
                    <h3 className="text-2xl font-bold text-text-primary mt-4">Formulir Pendaftaran Online</h3>
                </header>

                {timeLeft && (
                    <Card className="text-center mb-4 border-primary/50 bg-primary/5">
                        <p className="font-semibold text-text-secondary">Sisa Waktu Pendaftaran:</p>
                        <p className="text-2xl font-bold text-primary">{timeLeft}</p>
                    </Card>
                )}

                {!successMessage ? (
                    <form onSubmit={handleSubmit}>
                        <Card className="mb-4">
                            <h2 className="text-xl font-bold mb-4">Data Atlet</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <Input label="Nama Lengkap Atlet" id="name" name="name" value={formData.name} onChange={handleFormChange} onBlur={handleNameBlur} required />
                                    {isCheckingName && <p className="text-xs text-text-secondary mt-1">Mencari data atlet...</p>}
                                    {existingSwimmer && (
                                        <div className="text-xs text-green-600 dark:text-green-400 mt-1 p-2 bg-green-500/10 rounded-md">
                                            Data ditemukan dan diisi otomatis. Bukan atlet yang benar?{' '}
                                            <button type="button" onClick={clearAutoFilledData} className="underline font-semibold">Klik di sini</button> untuk mengisi manual.
                                        </div>
                                    )}
                                </div>
                                <Input label="Nama Tim" id="club" name="club" value={formData.club} onChange={handleFormChange} required />
                                <Input label="Tahun Lahir" id="birthYear" name="birthYear" type="number" value={formData.birthYear} onChange={handleFormChange} required />
                                <Select label="Jenis Kelamin" id="gender" name="gender" value={formData.gender} onChange={handleFormChange}>
                                    <option value="Male">Laki-laki (Male)</option>
                                    <option value="Female">Perempuan (Female)</option>
                                </Select>
                                 <Select label="Kelompok Umur (KU)" id="ageGroup" name="ageGroup" value={formData.ageGroup} onChange={handleFormChange} required>
                                    <option value="">-- Pilih KU Terlebih Dahulu --</option>
                                    {ageOptions.map((ku: string) => <option key={ku} value={ku}>{ku}</option>)}
                                </Select>
                            </div>
                        </Card>

                        <Card>
                            <h2 className="text-xl font-bold mb-4">Pilih Nomor Lomba</h2>
                            {!formData.ageGroup ? (
                                <div className="text-center py-10 bg-background/50 rounded-lg border-2 border-dashed border-border">
                                    <p className="text-text-secondary font-medium italic">Silakan pilih Kelompok Umur (KU) di atas terlebih dahulu untuk menampilkan nomor lomba yang tersedia.</p>
                                </div>
                            ) : Object.entries(groupedAvailableEvents).length > 0 ? (
                                <div className="space-y-2">
                                    {Object.entries(groupedAvailableEvents).map(([style, eventsInStyle]) => {
                                        // Calculate selected count for this style
                                        const selectedCountInStyle = eventsInStyle.filter(e => (selectedEvents[e.id] as any)?.selected).length;

                                        return (
                                        <div key={style} className="border border-border rounded-lg">
                                            <button
                                                type="button"
                                                onClick={() => handleAccordionToggle(style as SwimStyle)}
                                                className={`w-full flex justify-between items-center p-4 bg-background hover:bg-surface/50 transition-colors ${selectedCountInStyle > 0 ? 'bg-primary/5' : ''}`}
                                            >
                                                <h3 className={`text-lg font-semibold flex items-center ${selectedCountInStyle > 0 ? 'text-primary' : ''}`}>
                                                    {translateSwimStyle(style as SwimStyle)}
                                                    {selectedCountInStyle > 0 && (
                                                        <span className="ml-3 text-xs bg-primary text-white px-2 py-0.5 rounded-full">
                                                            {selectedCountInStyle} Dipilih
                                                        </span>
                                                    )}
                                                </h3>
                                                <ChevronDownIcon isOpen={openAccordion === style} />
                                            </button>
                                            {openAccordion === style && (
                                                <div className="p-4 space-y-4 animate-in fade-in slide-in-from-top-2 duration-200">
                                                    {eventsInStyle.map(event => (
                                                        <div key={event.id} className="border-b border-border last:border-b-0 pb-4 last:pb-0">
                                                            <div className="flex items-start">
                                                                <input
                                                                    type="checkbox"
                                                                    id={`event-${event.id}`}
                                                                    checked={(selectedEvents[event.id] as any)?.selected || false}
                                                                    onChange={() => handleEventSelectionChange(event.id)}
                                                                    className="h-5 w-5 rounded border-gray-300 text-primary focus:ring-primary mt-1"
                                                                />
                                                                <label htmlFor={`event-${event.id}`} className="ml-3 flex-grow cursor-pointer select-none">
                                                                    <span className="font-semibold text-text-primary">{formatEventName(event)}</span>
                                                                </label>
                                                            </div>
                                                            {(selectedEvents[event.id] as any)?.selected && (
                                                                <div className="mt-2 ml-8 grid grid-cols-3 md:grid-cols-4 gap-2 items-end">
                                                                    <Input label="Menit" id={`min-${event.id}`} type="number" min="0" value={(selectedEvents[event.id] as any).time.min} onChange={e => handleTimeChange(event.id, 'min', e.target.value)} />
                                                                    <Input label="Detik" id={`sec-${event.id}`} type="number" min="0" max="99" value={(selectedEvents[event.id] as any).time.sec} onChange={e => handleTimeChange(event.id, 'sec', e.target.value)} />
                                                                    <Input label="ss/100" id={`ms-${event.id}`} type="number" min="0" max="99" value={(selectedEvents[event.id] as any).time.ms} onChange={e => handleTimeChange(event.id, 'ms', e.target.value)} />
                                                                    <Button type="button" variant="secondary" onClick={() => handleSetNoTime(event.id)} className="whitespace-nowrap">No Time</Button>
                                                                </div>
                                                            )}
                                                        </div>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                    )})}
                                </div>
                            ) : (
                                <p className="text-text-secondary text-center py-4">Tidak ada nomor lomba yang tersedia untuk Jenis Kelamin dan KU yang dipilih, atau semua nomor lomba sudah terdaftar.</p>
                            )}
                        </Card>

                        <div className="mt-6">
                            {/* NEW: Selection Summary Card */}
                            {selectedEventsSummary.length > 0 && (
                                <Card className="mb-4 border-l-4 border-primary bg-primary/5 dark:bg-primary/10">
                                    <h3 className="font-bold text-lg mb-2 text-text-primary flex justify-between items-center">
                                        <span>Ringkasan Pilihan Anda</span>
                                        <span className="bg-primary text-white text-xs px-2 py-1 rounded-full">{selectedEventsSummary.length} Nomor</span>
                                    </h3>
                                    <div className="max-h-60 overflow-y-auto pr-2 custom-scrollbar">
                                        <ul className="space-y-1">
                                            {selectedEventsSummary.map(({ event, timeStr }) => (
                                                <li key={event.id} className="flex justify-between items-center text-sm border-b border-border/50 last:border-0 py-2">
                                                    <span className="text-text-primary">{formatEventName(event)}</span>
                                                    <span className="font-mono font-semibold bg-surface px-2 py-0.5 rounded border border-border/50 text-text-primary whitespace-nowrap ml-4">
                                                        {timeStr}
                                                    </span>
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                </Card>
                            )}

                            {error && <p className="text-red-500 text-center mb-4 font-semibold">{error}</p>}
                             <Card className="sticky bottom-4 z-10 shadow-2xl border-t-2 border-primary">
                                <div className="flex flex-col md:flex-row justify-between items-center gap-4">
                                    <p className="text-text-secondary text-sm md:text-base">
                                        Pastikan data atlet dan <span className="font-bold text-text-primary">{selectedEventCount}</span> nomor lomba yang dipilih sudah benar.
                                    </p>
                                    <Button type="submit" disabled={isSubmitting || !isFormValid} className="w-full md:w-auto px-8">
                                        {isSubmitting ? <Spinner /> : 'Kirim Pendaftaran'}
                                    </Button>
                                </div>
                            </Card>
                        </div>
                    </form>
                ) : (
                     <Card>
                        <div className="text-center p-4">
                            <div className="text-green-500 mx-auto h-16 w-16 mb-4">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-full w-full" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                                </svg>
                            </div>
                            <div className="text-text-primary">{successMessage}</div>
                            <Button onClick={() => setSuccessMessage('')} className="mt-6">Daftarkan Atlet Lain</Button>
                        </div>
                    </Card>
                )}

                <footer className="text-center p-4 mt-8">
                    <Button variant="secondary" onClick={onBackToLogin}>
                        &larr; Kembali ke Halaman Utama
                    </Button>
                </footer>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import type { CompetitionInfo, SwimEvent, Swimmer, FormattableEvent } from '../types';
import { getEventsForRegistration, processOnlineRegistration, findSwimmerByName, processParticipantUpload } from '../services/databaseService';
import { Card } from './ui/Card';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { Select } from './ui/Select';
import { Spinner } from './ui/Spinner';
import { formatEventName, toTitleCase, formatTime, translateSwimStyle, AGE_GROUP_OPTIONS } from '../constants';
import { SwimStyle, Gender } from '../types';

declare var XLSX: any;

interface OnlineRegistrationViewProps {
    competitionInfo: CompetitionInfo | null;
    onBackToLogin: () => void;
    onRegistrationSuccess: () => void;
}

type RegistrationTime = { min: string; sec: string; ms: string };
type SelectedEvents = Record<string, { selected: boolean; time: RegistrationTime }>;

interface OnlineRegistrationResponse {
    success: boolean;
    message: string;
    swimmer: Swimmer | null;
    previouslyRegisteredEvents?: FormattableEvent[];
}

const parseTimeToMs = (time: RegistrationTime): number => {
    const minutes = parseInt(time.min, 10) || 0;
    const seconds = parseInt(time.sec, 10) || 0;
    const hundredths = parseInt(time.ms, 10) || 0;
    if (minutes === 99 && seconds === 99 && hundredths === 99) {
        return 0; // Treat as No Time
    }
    return (minutes * 60 * 1000) + (seconds * 1000) + (hundredths * 10);
};

const ChevronDownIcon = ({ isOpen }: { isOpen: boolean }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={`h-6 w-6 transform transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
    </svg>
);

const UserIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
    </svg>
);

const UserGroupIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.653-.124-1.283-.356-1.857M7 20v-2c0-.653.124-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
    </svg>
);

export const OnlineRegistrationView: React.FC<OnlineRegistrationViewProps> = ({
    competitionInfo,
    onBackToLogin,
    onRegistrationSuccess,
}) => {
    const [regType, setRegType] = useState<'CHOICE' | 'INDIVIDUAL' | 'TEAM'>('CHOICE');
    const [localEvents, setLocalEvents] = useState<SwimEvent[]>([]);
    const [isDataLoading, setIsDataLoading] = useState(true);
    const [formData, setFormData] = useState({
        name: '',
        birthYear: new Date().getFullYear() - 10,
        gender: 'Male' as 'Male' | 'Female',
        club: '',
        ageGroup: '',
    });
    const [selectedEvents, setSelectedEvents] = useState<SelectedEvents>({});
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState('');
    const [successMessage, setSuccessMessage] = useState<React.ReactNode | string>('');

    // Team Registration States
    const [isDownloadingTemplate, setIsDownloadingTemplate] = useState(false);
    const [teamFile, setTeamFile] = useState<File | null>(null);
    const [isProcessingTeamFile, setIsProcessingTeamFile] = useState(false);
    const [teamUploadResult, setTeamUploadResult] = useState<{ newSwimmers: number; updatedSwimmers: number; errors: string[] } | null>(null);

    // State for auto-fill feature
    const [isCheckingName, setIsCheckingName] = useState(false);
    const [existingSwimmer, setExistingSwimmer] = useState<Swimmer | null>(null);

    // State for deadline countdown
    const [timeLeft, setTimeLeft] = useState('');
    const [isDeadlinePassed, setIsDeadlinePassed] = useState(false);

    // State for accordion
    const [openAccordion, setOpenAccordion] = useState<SwimStyle | null>(null);

    // Dynamic Age Groups Logic
    const ageOptions = useMemo(() => {
        if (competitionInfo?.ageGroups) {
            return competitionInfo.ageGroups.split('\n').map(s => s.trim()).filter(Boolean);
        }
        return AGE_GROUP_OPTIONS;
    }, [competitionInfo]);

    useEffect(() => {
        const fetchEvents = async () => {
            setIsDataLoading(true);
            const onlineEvents = await getEventsForRegistration();
            setLocalEvents(onlineEvents);
            setIsDataLoading(false);
        };

        fetchEvents();
    }, []);

    useEffect(() => {
        if (!competitionInfo?.registrationDeadline) {
            setIsDeadlinePassed(false);
            setTimeLeft('');
            return;
        }

        const deadline = new Date(competitionInfo.registrationDeadline);

        const updateCountdown = () => {
            const now = new Date();
            const difference = deadline.getTime() - now.getTime();

            if (difference <= 0) {
                setIsDeadlinePassed(true);
                setTimeLeft('Batas waktu pendaftaran telah berakhir.');
                return;
            }

            const days = Math.floor(difference / (1000 * 60 * 60 * 24));
            const hours = Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
            const minutes = Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60));
            const seconds = Math.floor((difference % (1000 * 60)) / 1000);

            setTimeLeft(`${days} hari ${hours} jam ${minutes} menit ${seconds} detik`);
        };

        updateCountdown();
        const intervalId = setInterval(updateCountdown, 1000);

        return () => clearInterval(intervalId);
    }, [competitionInfo?.registrationDeadline]);

    const handleAccordionToggle = (style: SwimStyle) => {
        setOpenAccordion(prev => (prev === style ? null : style));
    };

    const isFormValid = useMemo(() => {
        const hasPersonalInfo = formData.name.trim() !== '' && formData.club.trim() !== '' && formData.ageGroup !== '';
        const hasSelectedEvent = Object.values(selectedEvents).some((e: any) => (e as { selected: boolean }).selected);
        return hasPersonalInfo && hasSelectedEvent;
    }, [formData, selectedEvents]);

    const availableEvents = useMemo(() => {
        const registeredEventIds = new Set<string>();
        if (existingSwimmer) {
            localEvents.forEach(event => {
                if (event.entries.some(entry => entry.swimmerId === existingSwimmer.id)) {
                    registeredEventIds.add(event.id);
                }
            });
        }

        return localEvents
            .filter((event: SwimEvent) => {
                if (registeredEventIds.has(event.id)) return false;

                const genderMatch = event.gender === "Mixed" || 
                                   (formData.gender === "Male" && event.gender === "Men's") || 
                                   (formData.gender === "Female" && event.gender === "Women's");

                if (!genderMatch) return false;

                if (formData.ageGroup) {
                    return !event.category || event.category === formData.ageGroup;
                }

                return false;
            })
            .sort((a,b) => a.distance - b.distance || a.style.localeCompare(b.style));
    }, [localEvents, formData.gender, formData.ageGroup, existingSwimmer]);

    const groupedAvailableEvents = useMemo(() => {
        return availableEvents.reduce((acc: Record<SwimStyle, SwimEvent[]>, event: SwimEvent) => {
            const style = event.style;
            if (!acc[style]) {
                acc[style] = [];
            }
            acc[style].push(event);
            return acc;
        }, {} as Record<SwimStyle, SwimEvent[]>);
    }, [availableEvents]);

    const selectedEventCount = useMemo(() => {
        return Object.values(selectedEvents).filter((e: any) => (e as { selected: boolean }).selected).length;
    }, [selectedEvents]);

    const selectedEventsSummary = useMemo(() => {
        return (Object.entries(selectedEvents) as [string, any][])
            .filter(([_, val]) => (val as { selected: boolean }).selected)
            .map(([eventId, val]) => {
                const event = localEvents.find(e => e.id === eventId);
                if (!event) return null;

                const typedVal = val as { time: RegistrationTime };
                let timeStr = 'NT';
                const min = typedVal.time.min || '0';
                const sec = typedVal.time.sec || '0';
                const ms = typedVal.time.ms || '0';

                if (min === '99' && sec === '99' && ms === '99') {
                    timeStr = 'NT';
                } else {
                    timeStr = `${min.padStart(2, '0')}:${sec.padStart(2, '0')}.${ms.padStart(2, '0')}`;
                }

                return { event, timeStr };
            })
            .filter((item): item is { event: SwimEvent, timeStr: string } => item !== null)
            .sort((a, b) => {
                const styleCompare = a.event.style.localeCompare(b.event.style);
                if (styleCompare !== 0) return styleCompare;
                return a.event.distance - b.event.distance;
            });
    }, [selectedEvents, localEvents]);

    const handleFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        let finalValue: string | number = value;

        if (name === 'birthYear') {
            finalValue = parseInt(value);
        } else if (name === 'name' || name === 'club') {
            finalValue = toTitleCase(value);
        }

        setFormData(prev => ({ ...prev, [name]: finalValue }));
        setError('');
        setSuccessMessage('');
    };

    const handleEventSelectionChange = (eventId: string) => {
        setSelectedEvents(prev => ({
            ...prev,
            [eventId]: {
                selected: !prev[eventId]?.selected,
                time: prev[eventId]?.time || { min: '99', sec: '99', ms: '99' },
            },
        }));
    };

    const handleTimeChange = (eventId: string, part: keyof RegistrationTime, value: string) => {
        setSelectedEvents(prev => {
            const currentEvent = prev[eventId] || { selected: true, time: { min: '99', sec: '99', ms: '99' } };
            return {
                ...prev,
                [eventId]: {
                    ...currentEvent,
                    time: { ...currentEvent.time, [part]: value },
                },
            };
        });
    };

    const handleSetNoTime = (eventId: string) => {
        handleTimeChange(eventId, 'min', '99');
        handleTimeChange(eventId, 'sec', '99');
        handleTimeChange(eventId, 'ms', '99');
    };

    const handleNameBlur = async (e: React.FocusEvent<HTMLInputElement>) => {
        const swimmerName = e.target.value.trim();
        if (swimmerName.length < 3) {
            if (existingSwimmer) {
                setExistingSwimmer(null);
                setFormData(prev => ({ ...prev, club: '', birthYear: new Date().getFullYear() - 10, gender: 'Male', ageGroup: '' }));
            }
            return;
        }
        setIsCheckingName(true);
        const foundSwimmer = await findSwimmerByName(swimmerName);
        setIsCheckingName(false);
        if (foundSwimmer) {
            setFormData({
                name: foundSwimmer.name,
                club: foundSwimmer.club,
                birthYear: foundSwimmer.birthYear,
                gender: foundSwimmer.gender,
                ageGroup: foundSwimmer.ageGroup || '',
            });
            setExistingSwimmer(foundSwimmer);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setSuccessMessage('');
        setIsSubmitting(true);

        if (!formData.name.trim() || !formData.club.trim() || !formData.ageGroup) {
            setError('Data atlet (Nama, Tim, dan KU) wajib diisi lengkap.');
            setIsSubmitting(false);
            return;
        }

        const registrationsToSubmit = [];
        for (const [eventId, val] of Object.entries(selectedEvents)) {
            const eventValue = val as { selected: boolean; time: RegistrationTime };
            if (eventValue.selected) {
                const min = parseInt(eventValue.time.min, 10) || 0;
                const sec = parseInt(eventValue.time.sec, 10) || 0;
                const ms = parseInt(eventValue.time.ms, 10) || 0;

                if (sec >= 60 && !(min === 99 && sec === 99 && ms === 99)) {
                    setError(`Input detik harus di bawah 60.`);
                    setIsSubmitting(false);
                    return;
                }

                registrationsToSubmit.push({
                    eventId,
                    seedTime: parseTimeToMs(eventValue.time),
                });
            }
        }

        if (registrationsToSubmit.length === 0) {
            setError('Anda harus memilih setidaknya satu nomor lomba.');
            setIsSubmitting(false);
            return;
        }

        const result: OnlineRegistrationResponse = await processOnlineRegistration(formData, registrationsToSubmit);
        setIsSubmitting(false);

        if (result.success && result.swimmer) {
            const successText = (
                <div className="text-left">
                    <p className="font-bold text-lg mb-2">Pendaftaran untuk {result.swimmer.name} berhasil!</p>
                    <p className="mb-2">Anda sekarang terdaftar di nomor lomba yang dipilih.</p>
                </div>
            );
            setSuccessMessage(successText);
            onRegistrationSuccess();
            setFormData({ name: '', birthYear: new Date().getFullYear() - 10, gender: 'Male', club: '', ageGroup: '' });
            setSelectedEvents({});
        } else {
            setError(result.message || 'Terjadi kesalahan.');
        }
    };

    // --- Team Registration Logic ---
    const handleDownloadTemplate = () => {
        if (typeof XLSX === 'undefined') return;
        setIsDownloadingTemplate(true);

        const templateData = [{
            "Nama Atlet": "Contoh Atlet",
            "Tahun Lahir": 2010,
            "Jenis Kelamin (L/P)": "L",
            "Nama Tim": "Tim Keren",
            "KU": ageOptions[0] || "KU 1",
            "Nomor Lomba": formatEventName(localEvents[0]),
            "Waktu Unggulan (mm:ss.SS)": "01:25.50"
        }];

        const workbook = XLSX.utils.book_new();
        const wsTemplate = XLSX.utils.json_to_sheet(templateData);
        wsTemplate['!cols'] = [ { wch: 30 }, { wch: 15 }, { wch: 20 }, { wch: 25 }, { wch: 15 }, { wch: 45 }, { wch: 25 }];
        XLSX.utils.book_append_sheet(workbook, wsTemplate, "Form Pendaftaran");

        // Sheet info for reference
        const infoData = [
            ["DAFTAR NOMOR LOMBA", "", "DAFTAR KU"],
            ...localEvents.map((e, i) => [formatEventName(e), "", ageOptions[i] || ""])
        ];
        const wsInfo = XLSX.utils.aoa_to_sheet(infoData);
        XLSX.utils.book_append_sheet(workbook, wsInfo, "Daftar Nomor & KU");

        XLSX.writeFile(workbook, "Template_Pendaftaran_Kolektif.xlsx");
        setIsDownloadingTemplate(false);
    };

    const handleTeamFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setTeamFile(e.target.files[0]);
            setTeamUploadResult(null);
        }
    };

    const handleProcessTeamFile = () => {
        if (!teamFile || typeof XLSX === 'undefined') return;
        setIsProcessingTeamFile(true);
        setTeamUploadResult(null);

        const reader = new FileReader();
        reader.onload = async (e) => {
            try {
                const data = new Uint8Array(e.target?.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array' });
                const sheet = workbook.Sheets[workbook.SheetNames[0]];
                const json = XLSX.utils.sheet_to_json(sheet);

                const result = await processParticipantUpload(json);
                setTeamUploadResult(result);
                if (result.newSwimmers > 0 || result.updatedSwimmers > 0) {
                    onRegistrationSuccess();
                }
            } catch (err: any) {
                setTeamUploadResult({ newSwimmers: 0, updatedSwimmers: 0, errors: ["Gagal memproses file: " + err.message] });
            } finally {
                setIsProcessingTeamFile(false);
            }
        };
        reader.readAsArrayBuffer(teamFile);
    };

    const isRegistrationDisabled = isDeadlinePassed || !competitionInfo?.isRegistrationOpen;

    if (isDataLoading) {
        return (
            <div className="min-h-screen bg-background flex flex-col items-center justify-center p-4">
                <Spinner />
                <p className="text-text-secondary mt-4">Memuat data kompetisi...</p>
            </div>
        );
    }

     if (isRegistrationDisabled && !isDataLoading) {
        return (
             <div className="min-h-screen bg-gradient-to-br from-gray-100 to-slate-200 dark:from-slate-800 dark:to-gray-900 flex flex-col items-center justify-center p-4 text-center">
                <Card className="max-w-xl">
                    <h1 className="text-2xl font-bold text-primary mb-4">{competitionInfo?.eventName.split('\n')[0]}</h1>
                    <p className="text-lg text-red-500 font-semibold mb-2">Pendaftaran Online Saat Ini Ditutup</p>
                    <p className="text-text-secondary mb-6">
                        {timeLeft || 'Pendaftaran untuk kompetisi ini belum dibuka atau sudah berakhir.'}
                    </p>
                    <Button onClick={onBackToLogin}>Kembali ke Halaman Utama</Button>
                </Card>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gradient-to-br from-sky-100 to-blue-200 dark:from-slate-800 dark:to-sky-900 flex flex-col items-center p-4">
            <div className="w-full max-w-4xl mx-auto">
                <header className="text-center py-6">
                    {competitionInfo?.eventLogo && <img src={competitionInfo.eventLogo} alt="Logo" className="mx-auto h-20 md:h-24 object-contain mb-4" />}
                    <h1 className="text-3xl md:text-5xl font-extrabold text-primary tracking-tight">{competitionInfo?.eventName.split('\n')[0]}</h1>
                    <h2 className="text-xl md:text-2xl font-semibold text-text-secondary tracking-wide mt-1">{competitionInfo?.eventName.split('\n')[1]}</h2>
                    <h3 className="text-2xl font-bold text-text-primary mt-4">Pendaftaran Online</h3>
                </header>

                {timeLeft && (
